const MC_COUNTRIES = [
  { code: "SK", name: "Slovensko", flag: "\u{1F1F8}\u{1F1F0}" },
  { code: "CZ", name: "\u010Cesko", flag: "\u{1F1E8}\u{1F1FF}" },
  { code: "HU", name: "Ma\u010Farsko", flag: "\u{1F1ED}\u{1F1FA}" },
  { code: "RO", name: "Rumunsko", flag: "\u{1F1F7}\u{1F1F4}" },
  { code: "IT", name: "Taliansko", flag: "\u{1F1EE}\u{1F1F9}" },
  { code: "DE", name: "Nemecko", flag: "\u{1F1E9}\u{1F1EA}" },
  { code: "US", name: "USA", flag: "\u{1F1FA}\u{1F1F8}" },
  { code: "CH", name: "\u0160vaj\u010Diarsko", flag: "\u{1F1E8}\u{1F1ED}" },
];

function MailchimpSettingsTab() {
  const { toast } = useToast();

  const { data: mcSettings = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/config/mailchimp-settings"],
  });

  const { data: envKeyInfo } = useQuery<{ available: boolean; maskedKey?: string; serverPrefix?: string }>({
    queryKey: ["/api/config/mailchimp-env-key"],
  });

  const [editingCountry, setEditingCountry] = useState<string | null>(null);
  const [usingEnvKey, setUsingEnvKey] = useState(false);
  const [formData, setFormData] = useState<{ apiKey: string; serverPrefix: string; defaultAudienceId: string; isActive: boolean }>({
    apiKey: "",
    serverPrefix: "",
    defaultAudienceId: "",
    isActive: true,
  });
  const [testResult, setTestResult] = useState<{ success?: boolean; accountName?: string; error?: string } | null>(null);
  const [testLoading, setTestLoading] = useState(false);

  const [audiences, setAudiences] = useState<{ id: string; name: string; memberCount: number }[]>([]);
  const [audiencesLoading, setAudiencesLoading] = useState(false);

  const upsertMutation = useMutation({
    mutationFn: async (data: any) => {
      const res = await apiRequest("POST", "/api/config/mailchimp-settings", data);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/config/mailchimp-settings"] });
      toast({ title: "Mailchimp nastavenia uložené" });
      setEditingCountry(null);
      setTestResult(null);
    },
    onError: () => {
      toast({ title: "Chyba pri ukladaní", variant: "destructive" });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (countryCode: string) => {
      const res = await apiRequest("DELETE", `/api/config/mailchimp-settings/${countryCode}`);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/config/mailchimp-settings"] });
      toast({ title: "Konfigurácia odstránená" });
    },
  });

  const handleUseEnvKey = () => {
    if (envKeyInfo?.available) {
      setFormData(p => ({ ...p, apiKey: "__ENV__", serverPrefix: envKeyInfo.serverPrefix || "" }));
      setUsingEnvKey(true);
    }
  };

  const handleTest = async () => {
    const apiKey = usingEnvKey ? "__ENV__" : formData.apiKey;
    const serverPrefix = formData.serverPrefix;
    if (!apiKey || !serverPrefix) {
      toast({ title: "Zadajte API kľúč a server prefix", variant: "destructive" });
      return;
    }
    setTestLoading(true);
    setTestResult(null);
    try {
      const res = await apiRequest("POST", "/api/config/mailchimp-settings/test", {
        apiKey,
        serverPrefix,
      });
      const result = await res.json();
      setTestResult(result);
      if (result.success) {
        toast({ title: `Pripojenie úspešné: ${result.accountName}` });
        loadAudiences();
      }
    } catch {
      setTestResult({ success: false, error: "Chyba pripojenia" });
    }
    setTestLoading(false);
  };

  const loadAudiences = async () => {
    if (!editingCountry) return;
    setAudiencesLoading(true);
    try {
      const res = await fetch(`/api/config/mailchimp-settings/${editingCountry}/audiences`);
      if (res.ok) {
        const data = await res.json();
        setAudiences(data);
      }
    } catch {}
    setAudiencesLoading(false);
  };

  const handleEdit = (config: any) => {
    setEditingCountry(config.countryCode);
    setFormData({
      apiKey: config.apiKey || "",
      serverPrefix: config.serverPrefix || "",
      defaultAudienceId: config.defaultAudienceId || "",
      isActive: config.isActive !== false,
    });
    setTestResult(null);
    setAudiences([]);
  };

  const handleAddCountry = (countryCode: string) => {
    setEditingCountry(countryCode);
    setUsingEnvKey(false);
    setFormData({ apiKey: "", serverPrefix: "", defaultAudienceId: "", isActive: true });
    setTestResult(null);
    setAudiences([]);
  };

  const handleSave = () => {
    const apiKey = usingEnvKey ? "__ENV__" : formData.apiKey;
    if (!editingCountry || !apiKey || !formData.serverPrefix) return;
    upsertMutation.mutate({
      countryCode: editingCountry,
      apiKey,
      serverPrefix: formData.serverPrefix,
      defaultAudienceId: formData.defaultAudienceId || null,
      isActive: formData.isActive,
    });
    setUsingEnvKey(false);
  };

  const getConfigForCountry = (countryCode: string) =>
    mcSettings.find((c: any) => c.countryCode === countryCode);

  const configuredCountries = MC_COUNTRIES.filter(c => getConfigForCountry(c.code));
  const availableCountries = MC_COUNTRIES.filter(c => !getConfigForCountry(c.code));

  if (isLoading) return <div className="flex justify-center py-8"><Loader2 className="h-6 w-6 animate-spin" /></div>;

  return (
    <div className="space-y-6">
      <div className="p-4 border rounded-lg bg-card">
        <div className="flex items-center gap-3">
          <Mail className="h-5 w-5 text-muted-foreground" />
          <div>
            <h3 className="font-medium">Mailchimp Integrácia</h3>
            <p className="text-sm text-muted-foreground">
              Prepojenie s Mailchimp účtom pre každú krajinu. API kľúč nájdete v Mailchimp &gt; Account &gt; Extras &gt; API keys.
            </p>
          </div>
        </div>
      </div>

      {configuredCountries.map(country => {
        const config = getConfigForCountry(country.code)!;
        const isEditing = editingCountry === country.code;

        return (
          <div key={country.code} className="p-4 border rounded-lg">
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-2">
                <span className="text-lg">{country.flag}</span>
                <span className="font-medium">{country.name}</span>
                <Badge variant={config.isActive ? "default" : "secondary"} data-testid={`badge-mc-status-${country.code}`}>
                  {config.isActive ? "Aktívny" : "Neaktívny"}
                </Badge>
              </div>
              <div className="flex gap-2">
                <Button variant="outline" size="sm" onClick={() => handleEdit(config)} data-testid={`btn-edit-mc-${country.code}`}>
                  <Pencil className="h-4 w-4 mr-1" /> Upraviť
                </Button>
                <Button variant="outline" size="sm" onClick={() => deleteMutation.mutate(country.code)} data-testid={`btn-delete-mc-${country.code}`}>
                  <Trash2 className="h-4 w-4 mr-1" /> Odstrániť
                </Button>
              </div>
            </div>
            {isEditing ? (
              <div className="space-y-4 mt-4 p-4 bg-muted/50 rounded-lg">
                {envKeyInfo?.available && !usingEnvKey && (
                  <div className="flex items-center gap-3 p-3 bg-blue-50 dark:bg-blue-950/30 rounded-lg border border-blue-200 dark:border-blue-800">
                    <Key className="h-4 w-4 text-blue-600 flex-shrink-0" />
                    <div className="flex-1">
                      <p className="text-sm font-medium text-blue-700 dark:text-blue-400">MAILCHIMP_API_KEY je dostupný v prostredí</p>
                      <p className="text-xs text-blue-600 dark:text-blue-500">{envKeyInfo.maskedKey} (prefix: {envKeyInfo.serverPrefix})</p>
                    </div>
                    <Button size="sm" variant="outline" onClick={handleUseEnvKey} data-testid="btn-use-env-key">
                      Použiť ENV kľúč
                    </Button>
                  </div>
                )}
                {usingEnvKey && (
                  <div className="flex items-center gap-3 p-3 bg-green-50 dark:bg-green-950/30 rounded-lg border border-green-200 dark:border-green-800">
                    <CheckCircle2 className="h-4 w-4 text-green-600 flex-shrink-0" />
                    <div className="flex-1">
                      <p className="text-sm font-medium text-green-700 dark:text-green-400">Používa sa ENV kľúč: {envKeyInfo?.maskedKey}</p>
                      <p className="text-xs text-green-600 dark:text-green-500">Server prefix: {formData.serverPrefix}</p>
                    </div>
                    <Button size="sm" variant="ghost" onClick={() => { setUsingEnvKey(false); setFormData(p => ({ ...p, apiKey: "", serverPrefix: "" })); }} data-testid="btn-clear-env-key">
                      Zadať manuálne
                    </Button>
                  </div>
                )}
                {!usingEnvKey && (
                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <Label>API Kľúč</Label>
                      <Input
                        type="password"
                        value={formData.apiKey}
                        onChange={e => {
                          const val = e.target.value;
                          const parts = val.split("-");
                          const prefix = parts.length > 1 ? parts[parts.length - 1] : formData.serverPrefix;
                          setFormData(p => ({ ...p, apiKey: val, serverPrefix: prefix }));
                        }}
                        placeholder="xxxxxxxxxx-usXX"
                        data-testid="input-mc-apikey"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label>Server Prefix</Label>
                      <Input
                        value={formData.serverPrefix}
                        onChange={e => setFormData(p => ({ ...p, serverPrefix: e.target.value }))}
                        placeholder="us5"
                        data-testid="input-mc-server"
                      />
                      <p className="text-xs text-muted-foreground">Automaticky extrahovaný z API kľúča</p>
                    </div>
                  </div>
                )}
                <div className="flex items-center gap-4">
                  <Button variant="outline" size="sm" onClick={handleTest} disabled={testLoading} data-testid="btn-test-mc">
                    {testLoading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Zap className="h-4 w-4 mr-1" />}
                    Test pripojenia
                  </Button>
                  {testResult && (
                    <span className={`text-sm ${testResult.success ? "text-green-600" : "text-red-600"}`}>
                      {testResult.success ? `Pripojené: ${testResult.accountName}` : testResult.error}
                    </span>
                  )}
                </div>
                {audiences.length > 0 && (
                  <div className="space-y-2">
                    <Label>Predvolená Audience (zoznam)</Label>
                    <Select value={formData.defaultAudienceId} onValueChange={v => setFormData(p => ({ ...p, defaultAudienceId: v }))}>
                      <SelectTrigger data-testid="select-mc-audience">
                        <SelectValue placeholder="Vyberte audience..." />
                      </SelectTrigger>
                      <SelectContent>
                        {audiences.map(a => (
                          <SelectItem key={a.id} value={a.id}>
                            {a.name} ({a.memberCount} kontaktov)
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  </div>
                )}
                <div className="flex items-center gap-2">
                  <Switch
                    checked={formData.isActive}
                    onCheckedChange={v => setFormData(p => ({ ...p, isActive: v }))}
                    data-testid="switch-mc-active"
                  />
                  <Label>Aktívny</Label>
                </div>
                <div className="flex gap-2">
                  <Button size="sm" onClick={handleSave} disabled={upsertMutation.isPending} data-testid="btn-save-mc">
                    Uložiť
                  </Button>
                  <Button variant="outline" size="sm" onClick={() => setEditingCountry(null)}>Zrušiť</Button>
                </div>
              </div>
            ) : (
              <div className="text-sm text-muted-foreground space-y-1">
                <p>API: {config.apiKey}</p>
                <p>Server: {config.serverPrefix}</p>
                {config.defaultAudienceId && <p>Audience: {config.defaultAudienceId}</p>}
              </div>
            )}
          </div>
        );
      })}

      {availableCountries.length > 0 && (
        <div className="p-4 border rounded-lg border-dashed">
          <p className="text-sm text-muted-foreground mb-3">Pridať konfiguráciu pre krajinu:</p>
          <div className="flex flex-wrap gap-2">
            {availableCountries.map(c => (
              <Button key={c.code} variant="outline" size="sm" onClick={() => handleAddCountry(c.code)} data-testid={`btn-add-mc-${c.code}`}>
                <span className="mr-1">{c.flag}</span> {c.name}
              </Button>
            ))}
          </div>
        </div>
      )}

      {editingCountry && !getConfigForCountry(editingCountry) && (
        <div className="p-4 border rounded-lg bg-muted/50 space-y-4">
          <div className="flex items-center gap-2">
            <span className="text-lg">{MC_COUNTRIES.find(c => c.code === editingCountry)?.flag}</span>
            <span className="font-medium">{MC_COUNTRIES.find(c => c.code === editingCountry)?.name}</span>
          </div>
          {envKeyInfo?.available && !usingEnvKey && (
            <div className="flex items-center gap-3 p-3 bg-blue-50 dark:bg-blue-950/30 rounded-lg border border-blue-200 dark:border-blue-800">
              <Key className="h-4 w-4 text-blue-600 flex-shrink-0" />
              <div className="flex-1">
                <p className="text-sm font-medium text-blue-700 dark:text-blue-400">MAILCHIMP_API_KEY je dostupný v prostredí</p>
                <p className="text-xs text-blue-600 dark:text-blue-500">{envKeyInfo.maskedKey} (prefix: {envKeyInfo.serverPrefix})</p>
              </div>
              <Button size="sm" variant="outline" onClick={handleUseEnvKey} data-testid="btn-use-env-key-new">
                Použiť ENV kľúč
              </Button>
            </div>
          )}
          {usingEnvKey && (
            <div className="flex items-center gap-3 p-3 bg-green-50 dark:bg-green-950/30 rounded-lg border border-green-200 dark:border-green-800">
              <CheckCircle2 className="h-4 w-4 text-green-600 flex-shrink-0" />
              <div className="flex-1">
                <p className="text-sm font-medium text-green-700 dark:text-green-400">Používa sa ENV kľúč: {envKeyInfo?.maskedKey}</p>
                <p className="text-xs text-green-600 dark:text-green-500">Server prefix: {formData.serverPrefix}</p>
              </div>
              <Button size="sm" variant="ghost" onClick={() => { setUsingEnvKey(false); setFormData(p => ({ ...p, apiKey: "", serverPrefix: "" })); }}>
                Zadať manuálne
              </Button>
            </div>
          )}
          {!usingEnvKey && (
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label>API Kľúč</Label>
                <Input
                  type="password"
                  value={formData.apiKey}
                  onChange={e => {
                    const val = e.target.value;
                    const parts = val.split("-");
                    const prefix = parts.length > 1 ? parts[parts.length - 1] : formData.serverPrefix;
                    setFormData(p => ({ ...p, apiKey: val, serverPrefix: prefix }));
                  }}
                  placeholder="xxxxxxxxxx-usXX"
                  data-testid="input-mc-apikey-new"
                />
              </div>
              <div className="space-y-2">
                <Label>Server Prefix</Label>
                <Input
                  value={formData.serverPrefix}
                  onChange={e => setFormData(p => ({ ...p, serverPrefix: e.target.value }))}
                  placeholder="us5"
                  data-testid="input-mc-server-new"
                />
                <p className="text-xs text-muted-foreground">Automaticky extrahovaný z API kľúča</p>
              </div>
            </div>
          )}
          <div className="flex items-center gap-4">
            <Button variant="outline" size="sm" onClick={handleTest} disabled={testLoading} data-testid="btn-test-mc-new">
              {testLoading ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <Zap className="h-4 w-4 mr-1" />}
              Test pripojenia
            </Button>
            {testResult && (
              <span className={`text-sm ${testResult.success ? "text-green-600" : "text-red-600"}`}>
                {testResult.success ? `Pripojené: ${testResult.accountName}` : testResult.error}
              </span>
            )}
          </div>
          {audiences.length > 0 && (
            <div className="space-y-2">
              <Label>Predvolená Audience (zoznam)</Label>
              <Select value={formData.defaultAudienceId} onValueChange={v => setFormData(p => ({ ...p, defaultAudienceId: v }))}>
                <SelectTrigger data-testid="select-mc-audience-new">
                  <SelectValue placeholder="Vyberte audience..." />
                </SelectTrigger>
                <SelectContent>
                  {audiences.map(a => (
                    <SelectItem key={a.id} value={a.id}>
                      {a.name} ({a.memberCount} kontaktov)
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          )}
          <div className="flex gap-2">
            <Button size="sm" onClick={handleSave} disabled={upsertMutation.isPending || !formData.apiKey} data-testid="btn-save-mc-new">
              Uložiť
            </Button>
            <Button variant="outline" size="sm" onClick={() => setEditingCountry(null)}>Zrušiť</Button>
          </div>
        </div>
      )}
    </div>
  );
}

// ============================================
// GSM SENDER TAB
// ============================================

const GSM_COUNTRIES = [
  { code: "SK", name: "Slovensko", flag: "🇸🇰" },
  { code: "CZ", name: "Česko", flag: "🇨🇿" },
  { code: "HU", name: "Maďarsko", flag: "🇭🇺" },
  { code: "RO", name: "Rumunsko", flag: "🇷🇴" },
  { code: "IT", name: "Taliansko", flag: "🇮🇹" },
  { code: "DE", name: "Nemecko", flag: "🇩🇪" },
  { code: "US", name: "USA", flag: "🇺🇸" },
  { code: "CH", name: "Švajčiarsko", flag: "🇨🇭" },
];

function GsmSenderTab() {
  const { toast } = useToast();

  // Query for GSM configs
  const { data: gsmConfigs = [], isLoading: configsLoading } = useQuery<GsmSenderConfig[]>({
    queryKey: ["/api/config/gsm-sender-configs"],
  });

  // Query for BulkGate credit
  const { data: creditInfo, isLoading: creditLoading, refetch: refetchCredit } = useQuery<{ success: boolean; credit?: number; currency?: string; error?: string }>({
    queryKey: ["/api/integrations/bulkgate/credit"],
    staleTime: 60000,
  });

  // Upsert mutation
  const upsertMutation = useMutation({
    mutationFn: async (data: { countryCode: string; senderIdType: string; senderIdValue?: string }) => {
      const res = await apiRequest("POST", "/api/config/gsm-sender-configs", data);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/config/gsm-sender-configs"] });
      toast({ title: "Konfigurácia uložená" });
    },
    onError: () => {
      toast({ title: "Chyba pri ukladaní", variant: "destructive" });
    },
  });

  // Delete mutation
  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const res = await apiRequest("DELETE", `/api/config/gsm-sender-configs/${id}`);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/config/gsm-sender-configs"] });
      toast({ title: "Konfigurácia odstránená" });
    },
    onError: () => {
      toast({ title: "Chyba pri odstraňovaní", variant: "destructive" });
    },
  });

  // Local state for editing
  const [editingCountry, setEditingCountry] = useState<string | null>(null);
  const [formData, setFormData] = useState<{ senderIdType: string; senderIdValue: string }>({
    senderIdType: "gText",
    senderIdValue: "",
  });

  const handleEdit = (config: GsmSenderConfig) => {
    setEditingCountry(config.countryCode);
    setFormData({
      senderIdType: config.senderIdType,
      senderIdValue: config.senderIdValue || "",
    });
  };

  const handleSave = (countryCode: string) => {
    // Don't send value for sender types that don't need it (gSystem, gShort, gPush)
    const sendValue = needsValue(formData.senderIdType) ? formData.senderIdValue : undefined;
    upsertMutation.mutate({
      countryCode,
      senderIdType: formData.senderIdType,
      senderIdValue: sendValue || undefined,
    });
    setEditingCountry(null);
  };

  const handleAddCountry = (countryCode: string) => {
    setEditingCountry(countryCode);
    setFormData({ senderIdType: "gText", senderIdValue: "CBC" });
  };

  // Handle sender type change - clear value for types that don't need it
  const handleSenderTypeChange = (newType: string) => {
    if (!needsValue(newType)) {
      setFormData({ senderIdType: newType, senderIdValue: "" });
    } else {
      setFormData(prev => ({ ...prev, senderIdType: newType }));
    }
  };

  const getConfigForCountry = (countryCode: string) => 
    gsmConfigs.find(c => c.countryCode === countryCode);

  // Check if sender type needs a value
  const needsValue = (type: string) => {
    const senderType = GSM_SENDER_ID_TYPES.find(t => t.value === type);
    return senderType?.needsValue ?? false;
  };

  return (
    <div className="space-y-6">
      {/* BulkGate Credit Section */}
      <div className="p-4 border rounded-lg bg-card">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <Wallet className="h-5 w-5 text-muted-foreground" />
            <div>
              <h3 className="font-medium">BulkGate Kredit</h3>
              {creditLoading ? (
                <p className="text-sm text-muted-foreground">Načítavam...</p>
              ) : creditInfo?.success ? (
                <p className="text-lg font-semibold text-primary">
                  {creditInfo.credit?.toFixed(2)} {creditInfo.currency}
                </p>
              ) : (
                <p className="text-sm text-destructive">{creditInfo?.error || "Chyba pripojenia"}</p>
              )}
            </div>
          </div>
          <Button
            variant="outline"
            size="sm"
            onClick={() => refetchCredit()}
            disabled={creditLoading}
            data-testid="button-refresh-credit"
          >
            <RefreshCw className={`h-4 w-4 mr-2 ${creditLoading ? 'animate-spin' : ''}`} />
            Obnoviť
          </Button>
        </div>
      </div>

      {/* Country Sender Configurations */}
      <div>
        <h3 className="font-medium mb-4">Konfigurácia odosielateľa podľa krajiny</h3>
        <p className="text-sm text-muted-foreground mb-4">
          Nastavte typ SMS odosielateľa pre každú krajinu. Táto konfigurácia sa použije pri odosielaní SMS zákazníkom z danej krajiny.
        </p>

        {configsLoading ? (
          <div className="flex items-center justify-center py-8">
            <Loader2 className="h-6 w-6 animate-spin" />
          </div>
        ) : (
          <div className="border rounded-lg overflow-hidden">
            <table className="w-full">
              <thead className="bg-muted/50">
                <tr>
                  <th className="px-4 py-3 text-left text-sm font-medium">Krajina</th>
                  <th className="px-4 py-3 text-left text-sm font-medium">Typ odosielateľa</th>
                  <th className="px-4 py-3 text-left text-sm font-medium">Hodnota</th>
                  <th className="px-4 py-3 text-right text-sm font-medium">Akcie</th>
                </tr>
              </thead>
              <tbody className="divide-y">
                {GSM_COUNTRIES.map((country) => {
                  const config = getConfigForCountry(country.code);
                  const isEditing = editingCountry === country.code;

                  return (
                    <tr key={country.code} className="hover-elevate">
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <span className="text-xl">{country.flag}</span>
                          <span className="font-medium">{country.name}</span>
                        </div>
                      </td>
                      <td className="px-4 py-3">
                        {isEditing ? (
                          <Select
                            value={formData.senderIdType}
                            onValueChange={handleSenderTypeChange}
                          >
                            <SelectTrigger className="w-48" data-testid={`select-sender-type-${country.code}`}>
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              {GSM_SENDER_ID_TYPES.map((type) => (
                                <SelectItem key={type.value} value={type.value}>
                                  {type.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        ) : config ? (
                          <span className="text-sm">
                            {GSM_SENDER_ID_TYPES.find(t => t.value === config.senderIdType)?.label || config.senderIdType}
                          </span>
                        ) : (
                          <span className="text-sm text-muted-foreground">Nenastavené</span>
                        )}
                      </td>
                      <td className="px-4 py-3">
                        {isEditing ? (
                          needsValue(formData.senderIdType) ? (
                            <Input
                              value={formData.senderIdValue}
                              onChange={(e) => setFormData(prev => ({ ...prev, senderIdValue: e.target.value }))}
                              placeholder={formData.senderIdType === "gText" ? "CBC" : formData.senderIdType === "gProfile" ? "ID profilu" : "Telefónne číslo"}
                              className="w-40"
                              data-testid={`input-sender-value-${country.code}`}
                            />
                          ) : (
                            <span className="text-sm text-muted-foreground">—</span>
                          )
                        ) : config?.senderIdValue ? (
                          <span className="text-sm font-mono">{config.senderIdValue}</span>
                        ) : (
                          <span className="text-sm text-muted-foreground">—</span>
                        )}
                      </td>
                      <td className="px-4 py-3 text-right">
                        {isEditing ? (
                          <div className="flex items-center justify-end gap-2">
                            <Button
                              size="sm"
                              onClick={() => handleSave(country.code)}
                              disabled={upsertMutation.isPending || (needsValue(formData.senderIdType) && !formData.senderIdValue.trim())}
                              data-testid={`button-save-${country.code}`}
                            >
                              {upsertMutation.isPending ? <Loader2 className="h-4 w-4 animate-spin" /> : <Check className="h-4 w-4" />}
                            </Button>
                            <Button
                              size="sm"
                              variant="ghost"
                              onClick={() => setEditingCountry(null)}
                              data-testid={`button-cancel-${country.code}`}
                            >
                              <X className="h-4 w-4" />
                            </Button>
                          </div>
                        ) : config ? (
                          <div className="flex items-center justify-end gap-2">
                            <Button
                              size="icon"
                              variant="ghost"
                              onClick={() => handleEdit(config)}
                              data-testid={`button-edit-${country.code}`}
                            >
                              <Pencil className="h-4 w-4" />
                            </Button>
                            <Button
                              size="icon"
                              variant="ghost"
                              onClick={() => deleteMutation.mutate(config.id)}
                              disabled={deleteMutation.isPending}
                              data-testid={`button-delete-${country.code}`}
                            >
                              <Trash2 className="h-4 w-4" />
                            </Button>
                          </div>
                        ) : (
                          <Button
                            size="sm"
                            variant="outline"
                            onClick={() => handleAddCountry(country.code)}
                            data-testid={`button-add-${country.code}`}
                          >
                            <Plus className="h-4 w-4 mr-1" />
                            Nastaviť
                          </Button>
                        )}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

// ============================================
// MESSAGE TEMPLATES TAB
