interface MessageTemplate {
  id: string;
  name: string;
  description?: string;
  type: "email" | "sms";
  format: "text" | "html";
  subject?: string;
  content?: string;
  contentHtml?: string;
  categoryId?: string;
  language: string;
  tags?: string[];
  isDefault: boolean;
  isActive: boolean;
  usageCount: number;
  createdAt?: string;
  updatedAt?: string;
}

interface TemplateCategory {
  id: string;
  name: string;
  description?: string;
  icon?: string;
  color?: string;
  priority: number;
  isActive: boolean;
}

