// Couriers Tab - Multiple couriers per billing company
function BillingCompanyCouriersTab({ billingDetailsId }: { billingDetailsId: string }) {
  const { t } = useI18n();
  const { toast } = useToast();
  const [isAddingCourier, setIsAddingCourier] = useState(false);
  const [editingCourier, setEditingCourier] = useState<any>(null);
  const [deletingCourier, setDeletingCourier] = useState<any>(null);

  const { data: couriers = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/billing-details", billingDetailsId, "couriers"],
    queryFn: async () => {
      const res = await fetch(`/api/billing-details/${billingDetailsId}/couriers`, { credentials: "include" });
      return res.json();
    },
  });

  const createMutation = useMutation({
    mutationFn: (data: any) => apiRequest("POST", `/api/billing-details/${billingDetailsId}/couriers`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/billing-details", billingDetailsId, "couriers"] });
      setIsAddingCourier(false);
      toast({ title: t.common.success, description: "Courier created" });
    },
  });

  const updateMutation = useMutation({
    mutationFn: ({ id, data }: { id: string; data: any }) => 
      apiRequest("PATCH", `/api/billing-details/${billingDetailsId}/couriers/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/billing-details", billingDetailsId, "couriers"] });
      setEditingCourier(null);
      toast({ title: t.common.success, description: "Courier updated" });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (id: string) => apiRequest("DELETE", `/api/billing-details/${billingDetailsId}/couriers/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/billing-details", billingDetailsId, "couriers"] });
      setDeletingCourier(null);
      toast({ title: t.common.success, description: "Courier deleted" });
    },
  });

  if (isLoading) {
    return (
      <div className="flex items-center justify-center py-8">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  return (
    <div className="space-y-4">
      <div className="flex justify-end">
        <Button onClick={() => setIsAddingCourier(true)} data-testid="button-add-courier">
          <Plus className="mr-2 h-4 w-4" />
          {t.konfigurator.addCourier || "Add Courier"}
        </Button>
      </div>

      {couriers.length === 0 ? (
        <div className="text-center py-8 text-muted-foreground">
          {t.konfigurator.noCouriersAvailable || "No couriers available"}
        </div>
      ) : (
        <div className="space-y-2">
          {couriers.map((courier: any) => (
            <div key={courier.id} className="flex items-center justify-between p-3 bg-muted/50 rounded-lg">
              <div className="flex-1">
                <div className="flex items-center gap-2">
                  <span className="font-medium">{courier.name}</span>
                  {!courier.isActive && (
                    <Badge variant="secondary">{t.common.inactive}</Badge>
                  )}
                </div>
                <div className="text-sm text-muted-foreground flex flex-wrap gap-3 mt-1">
                  {courier.phone && <span>{courier.phone}</span>}
                  {courier.email && <span>{courier.email}</span>}
                </div>
                {courier.description && (
                  <div className="text-sm text-muted-foreground mt-1">{courier.description}</div>
                )}
              </div>
              <div className="flex gap-1">
                <Button variant="ghost" size="icon" onClick={() => setEditingCourier(courier)} data-testid={`button-edit-courier-${courier.id}`}>
                  <Pencil className="h-4 w-4" />
                </Button>
                <Button variant="ghost" size="icon" onClick={() => setDeletingCourier(courier)} data-testid={`button-delete-courier-${courier.id}`}>
                  <Trash2 className="h-4 w-4 text-destructive" />
                </Button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Add/Edit Courier Dialog */}
      <CourierFormDialog
        open={isAddingCourier || !!editingCourier}
        onOpenChange={(open) => {
          if (!open) {
            setIsAddingCourier(false);
            setEditingCourier(null);
          }
        }}
        courier={editingCourier}
        onSave={(data) => {
          if (editingCourier) {
            updateMutation.mutate({ id: editingCourier.id, data });
          } else {
            createMutation.mutate(data);
          }
        }}
        isPending={createMutation.isPending || updateMutation.isPending}
      />

      {/* Delete Confirmation */}
      <AlertDialog open={!!deletingCourier} onOpenChange={(open) => !open && setDeletingCourier(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t.konfigurator.deleteCourier || "Delete Courier"}</AlertDialogTitle>
            <AlertDialogDescription>
              {t.konfigurator.deleteCourierConfirm || "Are you sure you want to delete this courier?"}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t.common.cancel}</AlertDialogCancel>
            <AlertDialogAction
              onClick={() => deletingCourier && deleteMutation.mutate(deletingCourier.id)}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {deleteMutation.isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              {t.common.delete}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

// Courier Form Dialog
function CourierFormDialog({
  open,
  onOpenChange,
  courier,
  onSave,
  isPending,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  courier: any;
  onSave: (data: any) => void;
  isPending: boolean;
}) {
  const { t } = useI18n();
  const [formData, setFormData] = useState({
    name: "",
    phone: "",
    email: "",
    isActive: true,
    description: "",
  });

  useEffect(() => {
    if (courier) {
      setFormData({
        name: courier.name || "",
        phone: courier.phone || "",
        email: courier.email || "",
        isActive: courier.isActive ?? true,
        description: courier.description || "",
      });
    } else {
      setFormData({
        name: "",
        phone: "",
        email: "",
        isActive: true,
        description: "",
      });
    }
  }, [courier, open]);

  const handleSubmit = () => {
    if (!formData.name) return;
    onSave(formData);
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>
            {courier ? (t.konfigurator.editCourier || "Edit Courier") : (t.konfigurator.addCourier || "Add Courier")}
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <div className="space-y-2">
            <Label>{t.konfigurator.courierName || "Name"} *</Label>
            <Input 
              value={formData.name} 
              onChange={(e) => setFormData(p => ({ ...p, name: e.target.value }))} 
              data-testid="input-courier-name"
            />
          </div>

          <div className="space-y-2">
            <Label>{t.konfigurator.courierPhone || "Phone"}</Label>
            <Input 
              value={formData.phone} 
              onChange={(e) => setFormData(p => ({ ...p, phone: e.target.value }))} 
              data-testid="input-courier-phone"
            />
          </div>

          <div className="space-y-2">
            <Label>{t.konfigurator.courierEmail || "Email"}</Label>
            <Input 
              type="email"
              value={formData.email} 
              onChange={(e) => setFormData(p => ({ ...p, email: e.target.value }))} 
              data-testid="input-courier-email"
            />
          </div>

          <div className="space-y-2">
            <Label>{t.konfigurator.courierDescription || "Description"}</Label>
            <Textarea 
              value={formData.description} 
              onChange={(e) => setFormData(p => ({ ...p, description: e.target.value }))} 
              data-testid="input-courier-description"
            />
          </div>

          <div className="flex items-center space-x-2">
            <Switch 
              checked={formData.isActive} 
              onCheckedChange={(v) => setFormData(p => ({ ...p, isActive: v }))} 
              data-testid="switch-courier-active"
            />
            <Label>{t.common.active}</Label>
          </div>
        </div>

        <DialogFooter>
          <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
            {t.common.cancel}
          </Button>
          <Button onClick={handleSubmit} disabled={isPending || !formData.name} data-testid="button-save-courier">
            {isPending && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
            {t.common.save}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function EntityGraphTab() {
  const { toast } = useToast();
  const [entities, setEntities] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [segmentFilter, setSegmentFilter] = useState("all");
  const [selectedEntity, setSelectedEntity] = useState<any>(null);
  const [resolving, setResolving] = useState(false);

  useEffect(() => {
    fetch("/api/lead-entities?limit=200", { credentials: "include" }).then(r => r.json()).then(data => { setEntities(Array.isArray(data) ? data : []); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  const reload = () => { fetch("/api/lead-entities?limit=200", { credentials: "include" }).then(r => r.json()).then(data => setEntities(Array.isArray(data) ? data : [])); };

  const filtered = entities.filter(e => {
    if (segmentFilter !== "all" && e.segment !== segmentFilter) return false;
    if (search && !e.canonicalName?.toLowerCase().includes(search.toLowerCase()) && !e.primaryEmail?.toLowerCase().includes(search.toLowerCase())) return false;
    return true;
  });

  const segments = [...new Set(entities.map(e => e.segment).filter(Boolean))];

  return (
    <div className="space-y-4">
      <div className="flex gap-2 items-center flex-wrap">
        <Input data-testid="input-entity-search" placeholder="Hľadať entity..." value={search} onChange={e => setSearch(e.target.value)} className="max-w-xs" />
        <select data-testid="select-entity-segment" className="text-sm border rounded-md px-2 py-1.5 bg-background" value={segmentFilter} onChange={e => setSegmentFilter(e.target.value)}>
          <option value="all">Všetky segmenty</option>
          {segments.map(s => <option key={s} value={s}>{s}</option>)}
        </select>
        <Button data-testid="button-resolve-entities" variant="outline" size="sm" disabled={resolving} onClick={async () => {
          setResolving(true);
          try {
            const resp = await fetch("/api/lead-entities/resolve", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({}) });
            const data = await resp.json();
            toast({ title: "Entity resolution", description: `${data.created} vytvorených, ${data.merged} zlúčených` });
            reload();
          } catch (e: any) { toast({ title: "Chyba", description: e.message, variant: "destructive" }); }
          setResolving(false);
        }}>{resolving ? <Loader2 className="h-4 w-4 animate-spin mr-1" /> : <GitMerge className="h-4 w-4 mr-1" />} Resolve entity</Button>
        <Button data-testid="button-analyze-sources" variant="outline" size="sm" onClick={async () => {
          const resp = await fetch("/api/source-learning/analyze", { method: "POST", credentials: "include" });
          const data = await resp.json();
          toast({ title: "Analýza zdrojov", description: data.message });
        }}><Brain className="h-4 w-4 mr-1" /> Analyzovať zdroje</Button>
        <Button data-testid="button-calculate-scores" variant="outline" size="sm" onClick={async () => {
          const resp = await fetch("/api/contact-scores/calculate-all", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({}) });
          const data = await resp.json();
          toast({ title: "Skóre kontaktov", description: data.message });
        }}><Award className="h-4 w-4 mr-1" /> Vypočítať skóre</Button>
        <div className="ml-auto text-sm text-muted-foreground">{filtered.length} entít</div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <div className="lg:col-span-2">
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-base flex items-center gap-2"><Share2 className="h-4 w-4" /> Znalostný graf entít</CardTitle></CardHeader>
            <CardContent>
              {loading ? <div className="flex justify-center py-8"><Loader2 className="h-6 w-6 animate-spin" /></div> : filtered.length === 0 ? (
                <div className="text-center py-8 text-muted-foreground space-y-3">
                  <Share2 className="h-10 w-10 mx-auto opacity-40" />
                  <div>
                    <p className="font-medium text-foreground mb-1">Znalostný graf entít</p>
                    <p className="text-sm max-w-md mx-auto">
                      Entity graf automaticky spája dáta z rôznych zdrojov do jedného záznamu.
                      Napr. jedna nemocnica nájdená na webe, v katalógu aj v registri sa zlúči do 1 entity
                      s viacerými dôkazmi a skóre dôveryhodnosti.
                    </p>
                  </div>
                  <div className="text-xs space-y-1 max-w-sm mx-auto text-left bg-muted/50 rounded-lg p-3">
                    <p className="font-medium text-foreground">Ako začať:</p>
                    <p>1. Spustite vyhľadávanie v záložke "Lead Search"</p>
                    <p>2. Po dokončení kliknite "Resolve entity" — systém zlúči duplicity</p>
                    <p>3. Tu uvidíte graf so vzťahmi, skóre a zdrojmi</p>
                  </div>
                </div>
              ) : (
                <div className="space-y-1 max-h-[600px] overflow-y-auto">
                  {filtered.map(entity => (
                    <div key={entity.id} data-testid={`entity-row-${entity.id}`} className={cn("flex items-center gap-3 p-2 rounded-md cursor-pointer transition-colors", selectedEntity?.id === entity.id ? "bg-primary/10 border border-primary/20" : "hover:bg-muted/50")} onClick={() => {
                      fetch(`/api/lead-entities/${entity.id}`, { credentials: "include" }).then(r => r.json()).then(data => setSelectedEntity(data));
                    }}>
                      <div className={cn("h-8 w-8 rounded-full flex items-center justify-center text-xs font-medium", entity.entityType === "person" ? "bg-blue-100 dark:bg-blue-900/30 text-blue-700" : "bg-violet-100 dark:bg-violet-900/30 text-violet-700")}>
                        {entity.entityType === "person" ? <User className="h-4 w-4" /> : <Building2 className="h-4 w-4" />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="text-sm font-medium truncate">{entity.canonicalName}</div>
                        <div className="text-xs text-muted-foreground flex gap-2">
                          {entity.countryCode && <span>{entity.countryCode}</span>}
                          {entity.segment && <span>{entity.segment}</span>}
                          {entity.city && <span>{entity.city}</span>}
                        </div>
                      </div>
                      <div className="flex gap-2 items-center text-xs">
                        {entity.primaryEmail && <Mail className="h-3 w-3 text-green-600" />}
                        {entity.primaryPhone && <Phone className="h-3 w-3 text-blue-600" />}
                        <div className="flex items-center gap-1">
                          <span className="text-muted-foreground">Trust:</span>
                          <div className="w-12 h-1.5 bg-muted rounded-full overflow-hidden"><div className="h-full bg-green-500 rounded-full" style={{ width: `${entity.trustScore || 0}%` }} /></div>
                          <span className="text-[10px]">{entity.trustScore || 0}</span>
                        </div>
                        <span className="text-muted-foreground ml-1">{entity.totalSources}x</span>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        <div>
          {selectedEntity ? (
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-base flex items-center gap-2">
                  {selectedEntity.entityType === "person" ? <User className="h-4 w-4" /> : <Building2 className="h-4 w-4" />}
                  {selectedEntity.canonicalName}
                </CardTitle>
                <CardDescription>{selectedEntity.segment} {selectedEntity.countryCode && `| ${selectedEntity.countryCode}`} {selectedEntity.city && `| ${selectedEntity.city}`}</CardDescription>
              </CardHeader>
              <CardContent className="space-y-3">
                <div className="grid grid-cols-2 gap-2 text-xs">
                  <div className="p-2 bg-muted/50 rounded"><span className="text-muted-foreground block">Completeness</span><span className="font-medium text-sm">{selectedEntity.completenessScore || 0}%</span></div>
                  <div className="p-2 bg-muted/50 rounded"><span className="text-muted-foreground block">Trust</span><span className="font-medium text-sm">{selectedEntity.trustScore || 0}%</span></div>
                  <div className="p-2 bg-muted/50 rounded"><span className="text-muted-foreground block">Zdroje</span><span className="font-medium text-sm">{selectedEntity.totalSources || 1}</span></div>
                  <div className="p-2 bg-muted/50 rounded"><span className="text-muted-foreground block">IČO</span><span className="font-medium text-sm">{selectedEntity.ico || "—"}</span></div>
                </div>
                {selectedEntity.primaryEmail && <div className="flex items-center gap-2 text-sm"><Mail className="h-3 w-3 text-muted-foreground" />{selectedEntity.primaryEmail}</div>}
                {selectedEntity.primaryPhone && <div className="flex items-center gap-2 text-sm"><Phone className="h-3 w-3 text-muted-foreground" />{selectedEntity.primaryPhone}</div>}
                {selectedEntity.primaryWebsite && <div className="flex items-center gap-2 text-sm"><Globe className="h-3 w-3 text-muted-foreground" /><a href={selectedEntity.primaryWebsite} target="_blank" className="text-blue-600 hover:underline truncate">{selectedEntity.primaryWebsite}</a></div>}
                {selectedEntity.address && <div className="flex items-center gap-2 text-sm"><MapPin className="h-3 w-3 text-muted-foreground" />{selectedEntity.address}</div>}
                {selectedEntity.relations?.length > 0 && (
                  <div>
                    <h4 className="text-xs font-medium text-muted-foreground mb-1">Vzťahy ({selectedEntity.relations.length})</h4>
                    {selectedEntity.relations.map((rel: any) => (
                      <div key={rel.id} className="flex items-center gap-2 text-xs p-1.5 bg-muted/30 rounded mb-1">
                        <ArrowRight className="h-3 w-3 text-muted-foreground" />
                        <span className="text-muted-foreground">{rel.relationType}</span>
                        <span className="font-medium">{rel.relatedEntity?.canonicalName || `Entity #${rel.fromEntityId === selectedEntity.id ? rel.toEntityId : rel.fromEntityId}`}</span>
                      </div>
                    ))}
                  </div>
                )}
                {selectedEntity.evidences?.length > 0 && (
                  <div>
                    <h4 className="text-xs font-medium text-muted-foreground mb-1">Dôkazy ({selectedEntity.evidences.length})</h4>
                    {selectedEntity.evidences.slice(0, 10).map((ev: any) => (
                      <div key={ev.id} className="flex items-center justify-between text-xs p-1 border-b last:border-0">
                        <span><span className="text-muted-foreground">{ev.field}:</span> {ev.value}</span>
                        <span className="text-muted-foreground">{ev.confidence}%</span>
                      </div>
                    ))}
                  </div>
                )}
              </CardContent>
            </Card>
          ) : (
            <Card>
              <CardContent className="py-8 text-center text-muted-foreground text-sm">
                <Share2 className="h-6 w-6 mx-auto mb-2 opacity-50" />
                Vyberte entitu pre zobrazenie detailov
              </CardContent>
            </Card>
          )}
        </div>
      </div>
    </div>
  );
}

function FeedbackLearningTab() {
  const { toast } = useToast();
  const [patterns, setPatterns] = useState<any[]>([]);
  const [sourceLearning, setSourceLearning] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([
      fetch("/api/feedback-patterns", { credentials: "include" }).then(r => r.json()),
      fetch("/api/source-learning", { credentials: "include" }).then(r => r.json()),
    ]).then(([p, s]) => {
      setPatterns(Array.isArray(p) ? p : []);
      setSourceLearning(Array.isArray(s) ? s : []);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div className="flex justify-center py-12"><Loader2 className="h-6 w-6 animate-spin" /></div>;

  const goodPatterns = patterns.filter(p => p.patternType === "correct_contact" || p.patternType === "good_source" || p.patternType === "preferred_role");
  const badPatterns = patterns.filter(p => p.patternType === "incorrect_contact" || p.patternType === "bad_source");

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card><CardContent className="pt-4">
          <div className="text-2xl font-bold text-green-600">{goodPatterns.reduce((a, p) => a + (p.sampleCount || 0), 0)}</div>
          <div className="text-xs text-muted-foreground flex items-center gap-1"><ThumbsUp className="h-3 w-3" /> Pozitívne hodnotenia</div>
        </CardContent></Card>
        <Card><CardContent className="pt-4">
          <div className="text-2xl font-bold text-red-600">{badPatterns.reduce((a, p) => a + (p.sampleCount || 0), 0)}</div>
          <div className="text-xs text-muted-foreground flex items-center gap-1"><ThumbsDown className="h-3 w-3" /> Negatívne hodnotenia</div>
        </CardContent></Card>
        <Card><CardContent className="pt-4">
          <div className="text-2xl font-bold">{sourceLearning.length}</div>
          <div className="text-xs text-muted-foreground flex items-center gap-1"><Network className="h-3 w-3" /> Analyzované zdroje</div>
        </CardContent></Card>
        <Card><CardContent className="pt-4">
          <div className="text-2xl font-bold">{patterns.filter(p => p.patternType === "preferred_role").length}</div>
          <div className="text-xs text-muted-foreground flex items-center gap-1"><Users className="h-3 w-3" /> Preferované roly</div>
        </CardContent></Card>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-base flex items-center gap-2"><Brain className="h-4 w-4" /> Naučené vzory</CardTitle></CardHeader>
          <CardContent>
            {patterns.length === 0 ? (
              <div className="text-center py-6 text-muted-foreground text-sm">
                <Brain className="h-6 w-6 mx-auto mb-2 opacity-50" />
                Zatiaľ žiadne vzory. Systém sa začne učiť po označení výsledkov (palec hore/dole).
              </div>
            ) : (
              <div className="space-y-1 max-h-[400px] overflow-y-auto">
                {patterns.map(p => (
                  <div key={p.id} className="flex items-center justify-between p-2 rounded border text-xs">
                    <div className="flex items-center gap-2">
                      {(p.patternType === "correct_contact" || p.patternType === "good_source" || p.patternType === "preferred_role") ? <ThumbsUp className="h-3 w-3 text-green-600" /> : <ThumbsDown className="h-3 w-3 text-red-600" />}
                      <span className="font-medium">{p.patternType}</span>
                      {p.segment && <span className="text-muted-foreground">({p.segment})</span>}
                      {p.patternKey !== p.patternType && <span className="text-primary">{p.patternKey}</span>}
                    </div>
                    <div className="flex items-center gap-2">
                      <span className="text-muted-foreground">Váha: {p.weight}</span>
                      <span className="text-muted-foreground">Vzorky: {p.sampleCount}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-base flex items-center gap-2"><Network className="h-4 w-4" /> Kvalita zdrojov (učenie)</CardTitle></CardHeader>
          <CardContent>
            {sourceLearning.length === 0 ? (
              <div className="text-center py-6 text-muted-foreground text-sm">
                <Network className="h-6 w-6 mx-auto mb-2 opacity-50" />
                Spustite "Analyzovať zdroje" v záložke Entity Graf.
              </div>
            ) : (
              <div className="space-y-1 max-h-[400px] overflow-y-auto">
                {sourceLearning.map(s => (
                  <div key={s.id} className="p-2 rounded border text-xs space-y-1">
                    <div className="flex justify-between"><span className="font-medium">Zdroj #{s.sourceId}</span><span className="text-muted-foreground">{s.totalContactsFound} kontaktov</span></div>
                    <div className="grid grid-cols-4 gap-1">
                      <div><span className="text-muted-foreground">Email:</span> <div className="w-full h-1.5 bg-muted rounded-full mt-0.5"><div className="h-full bg-green-500 rounded-full" style={{ width: `${s.emailQuality}%` }} /></div></div>
                      <div><span className="text-muted-foreground">Telefón:</span> <div className="w-full h-1.5 bg-muted rounded-full mt-0.5"><div className="h-full bg-blue-500 rounded-full" style={{ width: `${s.phoneQuality}%` }} /></div></div>
                      <div><span className="text-muted-foreground">Adresa:</span> <div className="w-full h-1.5 bg-muted rounded-full mt-0.5"><div className="h-full bg-violet-500 rounded-full" style={{ width: `${s.addressQuality}%` }} /></div></div>
                      <div><span className="text-muted-foreground">Osoba:</span> <div className="w-full h-1.5 bg-muted rounded-full mt-0.5"><div className="h-full bg-orange-500 rounded-full" style={{ width: `${s.contactPersonQuality}%` }} /></div></div>
                    </div>
                    <div className="flex gap-2 text-[10px] text-muted-foreground">
                      <span>Kompletné: {s.completeContacts}</span>
                      <span>Duplicitné: {s.duplicateContacts}</span>
                      <span>Neplatné: {s.invalidContacts}</span>
                      {s.bestForSegments?.length > 0 && <span>Najlepšie pre: {s.bestForSegments.join(", ")}</span>}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

function LifecycleTab() {
  const { toast } = useToast();
  const [lifecycle, setLifecycle] = useState<any[]>([]);
  const [analytics, setAnalytics] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [stageFilter, setStageFilter] = useState("all");

  useEffect(() => {
    Promise.all([
      fetch("/api/lead-lifecycle", { credentials: "include" }).then(r => r.json()),
      fetch("/api/lead-lifecycle/analytics", { credentials: "include" }).then(r => r.json()),
    ]).then(([lc, an]) => {
      setLifecycle(Array.isArray(lc) ? lc : []);
      setAnalytics(an);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, []);

  const reload = () => {
    Promise.all([
      fetch("/api/lead-lifecycle", { credentials: "include" }).then(r => r.json()),
      fetch("/api/lead-lifecycle/analytics", { credentials: "include" }).then(r => r.json()),
    ]).then(([lc, an]) => { setLifecycle(Array.isArray(lc) ? lc : []); setAnalytics(an); });
  };

  if (loading) return <div className="flex justify-center py-12"><Loader2 className="h-6 w-6 animate-spin" /></div>;

  const stages = ["new", "contacted", "replied", "deal", "converted", "invalid"];
  const stageLabels: Record<string, string> = { new: "Nový", contacted: "Kontaktovaný", replied: "Odpovedal", deal: "Deal", converted: "Konvertovaný", invalid: "Neplatný" };
  const stageColors: Record<string, string> = { new: "bg-gray-500", contacted: "bg-blue-500", replied: "bg-green-500", deal: "bg-violet-500", converted: "bg-emerald-500", invalid: "bg-red-500" };
  const filtered = stageFilter === "all" ? lifecycle : lifecycle.filter(l => l.stage === stageFilter);

  return (
    <div className="space-y-4">
      {analytics && (
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-7 gap-3">
          <Card><CardContent className="pt-3 pb-3"><div className="text-xl font-bold">{analytics.total}</div><div className="text-[10px] text-muted-foreground">Celkovo leadov</div></CardContent></Card>
          <Card><CardContent className="pt-3 pb-3"><div className="text-xl font-bold text-blue-600">{analytics.contacted}</div><div className="text-[10px] text-muted-foreground">Kontaktovaných</div></CardContent></Card>
          <Card><CardContent className="pt-3 pb-3"><div className="text-xl font-bold text-green-600">{analytics.replied}</div><div className="text-[10px] text-muted-foreground">Odpovedalo</div></CardContent></Card>
          <Card><CardContent className="pt-3 pb-3"><div className="text-xl font-bold text-violet-600">{analytics.deals}</div><div className="text-[10px] text-muted-foreground">Deals</div></CardContent></Card>
          <Card><CardContent className="pt-3 pb-3"><div className="text-xl font-bold text-red-600">{analytics.invalid}</div><div className="text-[10px] text-muted-foreground">Neplatných</div></CardContent></Card>
          <Card><CardContent className="pt-3 pb-3"><div className="text-xl font-bold text-emerald-600">{analytics.conversionRate}%</div><div className="text-[10px] text-muted-foreground">Konverzný pomer</div></CardContent></Card>
          <Card><CardContent className="pt-3 pb-3"><div className="text-xl font-bold">{analytics.avgConversionDays}d</div><div className="text-[10px] text-muted-foreground">Priem. čas konverzie</div></CardContent></Card>
        </div>
      )}

      <div className="flex gap-1">
        <button className={cn("px-3 py-1 rounded-md text-xs border transition-colors", stageFilter === "all" ? "border-primary bg-primary/10 text-primary" : "hover:border-primary/30")} onClick={() => setStageFilter("all")}>Všetky ({lifecycle.length})</button>
        {stages.map(s => {
          const count = lifecycle.filter(l => l.stage === s).length;
          return <button key={s} className={cn("px-3 py-1 rounded-md text-xs border transition-colors", stageFilter === s ? "border-primary bg-primary/10 text-primary" : "hover:border-primary/30")} onClick={() => setStageFilter(s)}>{stageLabels[s] || s} ({count})</button>;
        })}
      </div>

      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-base flex items-center gap-2"><TrendingUp className="h-4 w-4" /> Životný cyklus leadov</CardTitle></CardHeader>
        <CardContent>
          {filtered.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground text-sm">
              <TrendingUp className="h-8 w-8 mx-auto mb-2 opacity-50" />
              <p>Žiadne záznamy. Leady sa do lifecycle dostanú po zlúčení do CRM.</p>
            </div>
          ) : (
            <div className="space-y-1 max-h-[500px] overflow-y-auto">
              {filtered.map(lc => (
                <div key={lc.id} data-testid={`lifecycle-row-${lc.id}`} className="flex items-center gap-3 p-2 rounded border text-xs">
                  <div className={cn("h-2 w-2 rounded-full", stageColors[lc.stage] || "bg-gray-400")} />
                  <span className="font-medium w-20">{stageLabels[lc.stage] || lc.stage}</span>
                  <span className="text-muted-foreground">{lc.crmType} #{lc.crmId}</span>
                  <span className="text-muted-foreground">{lc.segment}</span>
                  <span className="text-muted-foreground">{lc.country}</span>
                  <div className="flex-1" />
                  <div className="flex gap-1">
                    {!lc.wasContacted && lc.stage === "new" && (
                      <Button size="sm" variant="outline" className="h-5 text-[10px] px-1.5" data-testid={`lifecycle-contact-${lc.id}`} onClick={async () => {
                        await fetch(`/api/lead-lifecycle/${lc.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ wasContacted: true, stage: "contacted" }) });
                        reload();
                      }}><Mail className="h-3 w-3 mr-0.5" /> Kontaktovaný</Button>
                    )}
                    {lc.wasContacted && !lc.emailReplied && (
                      <Button size="sm" variant="outline" className="h-5 text-[10px] px-1.5" data-testid={`lifecycle-replied-${lc.id}`} onClick={async () => {
                        await fetch(`/api/lead-lifecycle/${lc.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ emailReplied: true, stage: "replied" }) });
                        reload();
                      }}><Check className="h-3 w-3 mr-0.5" /> Odpovedal</Button>
                    )}
                    {!lc.dealCreated && !lc.contactInvalid && (
                      <>
                        <Button size="sm" variant="outline" className="h-5 text-[10px] px-1.5 text-green-600 border-green-200" data-testid={`lifecycle-deal-${lc.id}`} onClick={async () => {
                          await fetch(`/api/lead-lifecycle/${lc.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ dealCreated: true, stage: "deal" }) });
                          reload();
                          toast({ title: "Deal vytvorený" });
                        }}><TrendingUp className="h-3 w-3 mr-0.5" /> Deal</Button>
                        <Button size="sm" variant="ghost" className="h-5 text-[10px] px-1.5 text-red-600" data-testid={`lifecycle-invalid-${lc.id}`} onClick={async () => {
                          await fetch(`/api/lead-lifecycle/${lc.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ contactInvalid: true, stage: "invalid", invalidReason: "manual" }) });
                          reload();
                        }}><X className="h-3 w-3 mr-0.5" /> Neplatný</Button>
                      </>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {analytics?.bySource?.length > 0 && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">Top zdroje (podľa konverzií)</CardTitle></CardHeader>
            <CardContent>
              {analytics.bySource.map((s: any, i: number) => (
                <div key={i} className="flex justify-between items-center text-xs p-1 border-b last:border-0">
                  <span>Zdroj #{s.sourceId}</span>
                  <div className="flex gap-3">
                    <span className="text-green-600">{s.conversions} konverzií</span>
                    <span className="text-red-600">{s.invalids} neplatných</span>
                    <span className="text-muted-foreground">{s.total} celkovo</span>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2"><CardTitle className="text-sm">Konverzie podľa segmentu</CardTitle></CardHeader>
            <CardContent>
              {analytics.bySegment?.map((s: any, i: number) => (
                <div key={i} className="flex justify-between items-center text-xs p-1 border-b last:border-0">
                  <span>{s.segment}</span>
                  <div className="flex gap-3">
                    <span className="text-green-600">{s.conversions} konverzií</span>
                    <span className="text-muted-foreground">{s.total} celkovo</span>
                    <span className="font-medium">{s.total > 0 ? Math.round((s.conversions / s.total) * 100) : 0}%</span>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        </div>
      )}
    </div>
  );
}

function LeadSearchTab() {
  const { t } = useI18n();
  const { toast } = useToast();
  const [activeSubTab, setActiveSubTab] = useState<"dashboard" | "search" | "sources" | "campaigns" | "templates" | "webhooks" | "entities" | "feedback" | "lifecycle">("dashboard");
  const [goalText, setGoalText] = useState("");
  const [goalParsing, setGoalParsing] = useState(false);
  const [parsedGoal, setParsedGoal] = useState<any>(null);
  const [searchForm, setSearchForm] = useState({
    name: "",
    targetModule: "hospitals" as "hospitals" | "clinics" | "collaborators",
    country: "",
    segment: "",
    location: "",
    keywords: "",
  });
  const [selectedJobId, setSelectedJobId] = useState<number | null>(null);
  const [previewResult, setPreviewResult] = useState<any>(null);
  const [isAssigning, setIsAssigning] = useState(false);
  const [existingMatches, setExistingMatches] = useState<any[]>([]);
  const [matchLoading, setMatchLoading] = useState(false);
  const [selectedMatch, setSelectedMatch] = useState<any>(null);
  const [selectedChanges, setSelectedChanges] = useState<Record<string, boolean>>({});
  const [assignModule, setAssignModule] = useState<string>("");
  const [selectedFields, setSelectedFields] = useState<Record<string, boolean>>({});
  const [aiSuggesting, setAiSuggesting] = useState(false);
  const [aiSuggestions, setAiSuggestions] = useState<any[]>([]);
  const [selectedSuggestions, setSelectedSuggestions] = useState<number[]>([]);
  const [sourceForm, setSourceForm] = useState({ url: "", name: "", type: "directory", countryCode: "", segment: "" });
  const [campaignForm, setCampaignForm] = useState({ name: "", targetModule: "hospitals", country: "", segment: "", location: "", keywords: "", schedule: "weekly" });
  const [expandedCampaign, setExpandedCampaign] = useState<number | null>(null);
  const [historyCampaign, setHistoryCampaign] = useState<{ id: number; name: string } | null>(null);
  const [historyJobId, setHistoryJobId] = useState<number | null>(null);
  const [historyJobName, setHistoryJobName] = useState<string>("");
  const [editingSource, setEditingSource] = useState<any>(null);
  const [aiSourceSuggestions, setAiSourceSuggestions] = useState<any[]>([]);
  const [aiSourceLoading, setAiSourceLoading] = useState(false);
  const [aiSourceFilter, setAiSourceFilter] = useState({ country: "", segment: "", targetModule: "hospitals", depth: "standard" as string });
  const [showSearchParams, setShowSearchParams] = useState(false);
  const [searchParams, setSearchParams] = useState({
    queryCount: 40,
    googlePages: 6,
    retryThreshold: 100,
    maxPagesToScrape: 200,
    deepCrawlDirectories: 20,
    deepCrawlLinksPerDir: 50,
    deepCrawlMaxSubpages: 150,
    paginationDepth: 15,
    contactPageDomains: 80,
    domainExpansionTopN: 15,
    domainExpansionLinksPerDomain: 30,
    aiFirstPassPages: 40,
    aiPassBatchSize: 20,
    enableCityQueries: true,
    enableDomainExpansion: true,
    enableRuleExtraction: true,
  });
  const searchParamsMeta: Record<string, { min: number; max: number; rec: number; label: string; desc: string; unit: string; category: string }> = {
    queryCount: { min: 10, max: 100, rec: 40, label: "Vyhľadávacie frázy", desc: "Koľko rôznych Google/Bing dopytov sa vygeneruje", unit: "fráz", category: "discovery" },
    googlePages: { min: 1, max: 10, rec: 6, label: "Google stránky/dopyt", desc: "Koľko stránok výsledkov sa prehľadá pre každý dopyt", unit: "stránok", category: "discovery" },
    retryThreshold: { min: 20, max: 300, rec: 100, label: "Retry prah", desc: "Pod koľko URL sa spustí opakované vyhľadávanie", unit: "URL", category: "discovery" },
    maxPagesToScrape: { min: 30, max: 500, rec: 200, label: "Max stránok na scrape", desc: "Maximálny počet stránok na stiahnutie", unit: "stránok", category: "scraping" },
    deepCrawlDirectories: { min: 5, max: 50, rec: 20, label: "Katalógy na deep crawl", desc: "Koľko katalógov sa prehľadá do hĺbky", unit: "katalógov", category: "scraping" },
    deepCrawlLinksPerDir: { min: 10, max: 100, rec: 50, label: "Linkov na katalóg", desc: "Koľko podstránok z každého katalógu", unit: "linkov", category: "scraping" },
    deepCrawlMaxSubpages: { min: 30, max: 500, rec: 150, label: "Max deep crawl stránok", desc: "Celkový limit podstránok z deep crawl", unit: "stránok", category: "scraping" },
    paginationDepth: { min: 3, max: 30, rec: 15, label: "Hĺbka paginácie", desc: "Do koľkej stránky sa prehľadá paginácia", unit: "strán", category: "scraping" },
    contactPageDomains: { min: 20, max: 200, rec: 80, label: "Kontaktné stránky", desc: "Koľko domén sa skontroluje na /kontakt", unit: "domén", category: "scraping" },
    domainExpansionTopN: { min: 5, max: 30, rec: 15, label: "Top domény na expanziu", desc: "Koľko najbohatších domén sa ďalej prehľadá", unit: "domén", category: "expansion" },
    domainExpansionLinksPerDomain: { min: 10, max: 80, rec: 30, label: "Linkov na expanziu", desc: "Ďalšie podstránky z každej bohatej domény", unit: "linkov", category: "expansion" },
    aiFirstPassPages: { min: 10, max: 60, rec: 40, label: "AI 1. pass stránky", desc: "Koľko stránok sa pošle AI na prvú extrakciu", unit: "stránok", category: "ai" },
    aiPassBatchSize: { min: 10, max: 40, rec: 20, label: "AI veľkosť dávky", desc: "Stránky v každom ďalšom AI passe", unit: "stránok", category: "ai" },
  };

  const { data: analytics } = useQuery<any>({ queryKey: ["/api/lead-search/analytics"] });
  const { data: leadSources = [], refetch: refetchSources } = useQuery<any[]>({ queryKey: ["/api/lead-sources"] });
  const { data: leadCampaigns = [], refetch: refetchCampaigns } = useQuery<any[]>({ queryKey: ["/api/lead-campaigns"] });
  const { data: queryTemplatesList = [], refetch: refetchTemplates } = useQuery<any[]>({ queryKey: ["/api/query-templates"] });
  const { data: webhooksList = [], refetch: refetchWebhooks } = useQuery<any[]>({ queryKey: ["/api/webhooks"] });
  const [webhookForm, setWebhookForm] = useState({ name: "", url: "", events: ["*"], secret: "" });
  const [showWebhookForm, setShowWebhookForm] = useState(false);
  const [templateSeeded, setTemplateSeeded] = useState(false);
  const [reviewFilter, setReviewFilter] = useState<string>("all");

  const getAiSuggestions = async () => {
    setAiSuggesting(true);
    setAiSuggestions([]);
    setSelectedSuggestions([]);
    try {
      const resp = await fetch("/api/lead-search/ai-suggest", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ targetModule: searchForm.targetModule, country: searchForm.country }),
      });
      if (resp.ok) {
        const data = await resp.json();
        setAiSuggestions(data.suggestions || []);
      } else {
        toast({ title: "Nepodarilo sa získať AI návrhy", variant: "destructive" });
      }
    } catch {
      toast({ title: "Chyba pri generovaní návrhov", variant: "destructive" });
    } finally {
      setAiSuggesting(false);
    }
  };

  const toggleSuggestion = (idx: number) => {
    setSelectedSuggestions(prev =>
      prev.includes(idx) ? prev.filter(i => i !== idx) : [...prev, idx]
    );
  };

  const applySelectedSuggestions = () => {
    if (selectedSuggestions.length === 0) return;
    const selected = selectedSuggestions.map(i => aiSuggestions[i]).filter(Boolean);
    const segments = [...new Set(selected.map(s => s.segment).filter(Boolean))];
    const locations = [...new Set(selected.map(s => s.location).filter(Boolean))];
    const allKeywords = [...new Set(selected.flatMap(s => (s.keywords || "").split(",").map((k: string) => k.trim())).filter(Boolean))];
    const names = selected.map(s => s.name).filter(Boolean);

    setSearchForm({
      ...searchForm,
      name: names.length === 1 ? names[0] : `${searchForm.targetModule === "hospitals" ? "Nemocnice" : searchForm.targetModule === "clinics" ? "Ambulancie" : "Spolupracovníci"} - ${locations[0] || "Hľadanie"} (${selected.length} scenárov)`,
      segment: segments.join(", "),
      location: locations.join(", "),
      keywords: allKeywords.slice(0, 10).join(", "),
    });
    setAiSuggestions([]);
    setSelectedSuggestions([]);
    toast({ title: `${selected.length} AI návrhov skombinovaných — spúšťam vyhľadávanie...` });
    setTimeout(() => {
      const finalForm = {
        name: names.length === 1 ? names[0] : `${searchForm.targetModule === "hospitals" ? "Nemocnice" : searchForm.targetModule === "clinics" ? "Ambulancie" : "Spolupracovníci"} - ${locations[0] || "Hľadanie"} (${selected.length} scenárov)`,
        targetModule: searchForm.targetModule, country: searchForm.country,
        segment: segments.join(", "), location: locations.join(", "), keywords: allKeywords.slice(0, 10).join(", "),
      };
      fetch("/api/lead-search/start", {
        method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include",
        body: JSON.stringify({ ...finalForm, searchParams }),
      }).then(r => r.json()).then(data => {
        if (data.jobId) { toast({ title: "Vyhľadávanie spustené", description: `Job #${data.jobId}` }); refetchJobs(); }
        else toast({ title: "Chyba", description: data.error, variant: "destructive" });
      }).catch(e => toast({ title: "Chyba", description: e.message, variant: "destructive" }));
    }, 200);
  };

  const applySingleSuggestion = (s: any) => {
    const form = {
      ...searchForm,
      name: s.name || searchForm.name,
      segment: s.segment || "",
      location: s.location || "",
      keywords: s.keywords || "",
    };
    setSearchForm(form);
    setAiSuggestions([]);
    setSelectedSuggestions([]);
    toast({ title: "AI návrh aplikovaný — spúšťam vyhľadávanie..." });
    setTimeout(() => {
      fetch("/api/lead-search/start", {
        method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include",
        body: JSON.stringify({ name: form.name || `${form.segment} ${form.location}`, targetModule: form.targetModule, country: form.country, segment: form.segment, location: form.location, keywords: form.keywords, searchParams }),
      }).then(r => r.json()).then(data => {
        if (data.jobId) { toast({ title: "Vyhľadávanie spustené", description: `Job #${data.jobId}` }); refetchJobs(); }
        else toast({ title: "Chyba", description: data.error, variant: "destructive" });
      }).catch(e => toast({ title: "Chyba", description: e.message, variant: "destructive" }));
    }, 200);
  };

  const { data: jobs = [], refetch: refetchJobs } = useQuery<any[]>({
    queryKey: ["/api/lead-search/jobs"],
  });

  const { data: results = [], refetch: refetchResults } = useQuery<any[]>({
    queryKey: ["/api/lead-search/jobs", selectedJobId, "results"],
    queryFn: async () => {
      if (!selectedJobId) return [];
      const resp = await fetch(`/api/lead-search/jobs/${selectedJobId}/results`, { credentials: "include" });
      const data = await resp.json();
      return Array.isArray(data) ? data : [];
    },
    enabled: !!selectedJobId,
  });
  const [stoppingJob, setStoppingJob] = useState(false);

  const selectedJob = jobs.find((j: any) => j.id === selectedJobId);

  useEffect(() => {
    if (selectedJob?.status === "running") {
      const interval = setInterval(() => {
        refetchJobs();
        if (selectedJobId) refetchResults();
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [selectedJob?.status, selectedJobId]);

  const startSearch = async () => {
    if (!searchForm.name) {
      toast({ title: "Zadajte názov vyhľadávania", variant: "destructive" });
      return;
    }
    try {
      const resp = await fetch("/api/lead-search/jobs", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ ...searchForm, searchParams }),
      });
      if (!resp.ok) throw new Error("Failed");
      const job = await resp.json();
      toast({ title: "Vyhľadávanie spustené" });
      setSelectedJobId(job.id);
      refetchJobs();
      setSearchForm({ name: "", targetModule: "hospitals", country: "", segment: "", location: "", keywords: "" });
    } catch (e) {
      toast({ title: "Chyba pri spustení vyhľadávania", variant: "destructive" });
    }
  };

  const confirmAssign = async () => {
    if (!previewResult) return;
    setIsAssigning(true);
    try {
      const enabledFields = Object.entries(selectedFields).filter(([_, v]) => v).map(([k]) => k);
      const resp = await fetch(`/api/lead-search/results/${previewResult.id}/assign`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({ targetModule: assignModule || selectedJob?.targetModule || "hospitals", selectedFields: enabledFields }),
      });
      if (!resp.ok) throw new Error("Failed");
      const moduleLabel = assignModule === "hospitals" ? "Nemocnice" : assignModule === "clinics" ? "Ambulancie" : "Spolupracovníci";
      toast({ title: `Kontakt vytvorený v module ${moduleLabel}` });
      setPreviewResult(null);
      setExistingMatches([]);
      setSelectedMatch(null);
      refetchResults();
      refetchJobs();
    } catch (e) {
      toast({ title: "Chyba pri priradení", variant: "destructive" });
    } finally {
      setIsAssigning(false);
    }
  };

  const updateExisting = async () => {
    if (!previewResult || !selectedMatch) return;
    const changesToApply: Record<string, { new: string }> = {};
    for (const [field, checked] of Object.entries(selectedChanges)) {
      if (checked && selectedMatch.changes[field]) {
        changesToApply[field] = { new: selectedMatch.changes[field].new };
      }
    }
    if (Object.keys(changesToApply).length === 0) {
      toast({ title: "Vyberte aspoň jednu zmenu na aktualizáciu", variant: "destructive" });
      return;
    }
    setIsAssigning(true);
    try {
      const resp = await fetch(`/api/lead-search/results/${previewResult.id}/update-existing`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          existingId: selectedMatch.id,
          targetModule: selectedJob?.targetModule,
          selectedChanges: changesToApply,
        }),
      });
      if (!resp.ok) throw new Error("Failed");
      toast({ title: "Existujúci záznam úspešne aktualizovaný" });
      setPreviewResult(null);
      setExistingMatches([]);
      setSelectedMatch(null);
      refetchResults();
      refetchJobs();
    } catch (e) {
      toast({ title: "Chyba pri aktualizácii", variant: "destructive" });
    } finally {
      setIsAssigning(false);
    }
  };

  const getAiSourceSuggestions = async () => {
    setAiSourceLoading(true);
    setAiSourceSuggestions([]);
    try {
      const resp = await fetch("/api/lead-sources/ai-suggest", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify(aiSourceFilter),
      });
      if (resp.ok) {
        const data = await resp.json();
        setAiSourceSuggestions(data);
      }
    } catch (err) { console.error("AI source suggest error:", err); }
    setAiSourceLoading(false);
  };

  const addSuggestedSource = async (suggestion: any) => {
    try {
      const resp = await fetch("/api/lead-sources", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        credentials: "include",
        body: JSON.stringify({
          url: suggestion.url,
          name: suggestion.name,
          type: suggestion.type || "directory",
          countryCode: suggestion.countryCode || "",
          segment: suggestion.segment || "",
        }),
      });
      if (resp.ok) {
        refetchSources();
        setAiSourceSuggestions(prev => prev.filter(s => s.url !== suggestion.url));
      }
    } catch (err) { console.error("Add suggested source error:", err); }
  };

  const addAllSuggestedSources = async () => {
    for (const s of aiSourceSuggestions) {
      await addSuggestedSource(s);
    }
    setAiSourceSuggestions([]);
  };

  const createSource = async () => {
    if (!sourceForm.url || !sourceForm.name) {
      toast({ title: "Vyplňte URL a názov zdroja", variant: "destructive" });
      return;
    }
    try {
      const resp = await fetch("/api/lead-sources", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify(sourceForm) });
      if (!resp.ok) throw new Error("Failed");
      toast({ title: "Zdroj pridaný" });
      setSourceForm({ url: "", name: "", type: "directory", countryCode: "", segment: "" });
      refetchSources();
    } catch { toast({ title: "Chyba pri vytváraní zdroja", variant: "destructive" }); }
  };

  const toggleSourceStatus = async (source: any) => {
    try {
      const newStatus = source.status === "active" ? "blacklisted" : "active";
      const resp = await fetch(`/api/lead-sources/${source.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ status: newStatus }) });
      if (!resp.ok) throw new Error("Failed");
      refetchSources();
    } catch { toast({ title: "Chyba pri zmene stavu", variant: "destructive" }); }
  };

  const deleteSource = async (id: number) => {
    try {
      const resp = await fetch(`/api/lead-sources/${id}`, { method: "DELETE", credentials: "include" });
      if (!resp.ok) throw new Error("Failed");
      refetchSources();
    } catch { toast({ title: "Chyba pri mazaní", variant: "destructive" }); }
  };

  const createCampaign = async () => {
    if (!campaignForm.name) {
      toast({ title: "Vyplňte názov kampane", variant: "destructive" });
      return;
    }
    try {
      const resp = await fetch("/api/lead-campaigns", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify(campaignForm) });
      if (!resp.ok) throw new Error("Failed");
      toast({ title: "Kampaň vytvorená" });
      setCampaignForm({ name: "", targetModule: "hospitals", country: "", segment: "", location: "", keywords: "", schedule: "weekly" });
      refetchCampaigns();
    } catch { toast({ title: "Chyba pri vytváraní kampane", variant: "destructive" }); }
  };

  const toggleCampaign = async (campaign: any) => {
    try {
      const resp = await fetch(`/api/lead-campaigns/${campaign.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ isActive: !campaign.isActive }) });
      if (!resp.ok) throw new Error("Failed");
      refetchCampaigns();
    } catch { toast({ title: "Chyba pri zmene stavu", variant: "destructive" }); }
  };

  const deleteCampaign = async (id: number) => {
    try {
      const resp = await fetch(`/api/lead-campaigns/${id}`, { method: "DELETE", credentials: "include" });
      if (!resp.ok) throw new Error("Failed");
      refetchCampaigns();
    } catch { toast({ title: "Chyba pri mazaní", variant: "destructive" }); }
  };

  const updateSource = async (source: any) => {
    try {
      const resp = await fetch(`/api/lead-sources/${source.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ name: source.name, url: source.url, type: source.type, countryCode: source.countryCode, segment: source.segment }) });
      if (!resp.ok) throw new Error("Failed");
      setEditingSource(null);
      refetchSources();
      toast({ title: "Zdroj aktualizovaný" });
    } catch { toast({ title: "Chyba pri úprave", variant: "destructive" }); }
  };

  const CampaignHistory = ({ campaignId }: { campaignId: number }) => {
    const { data: history = [] } = useQuery<any[]>({ queryKey: [`/api/lead-campaigns/${campaignId}/history`] });
    return (
      <div className="mt-3 border-t pt-3">
        <div className="text-xs font-medium mb-2">História behov</div>
        {history.length === 0 ? (
          <div className="text-xs text-muted-foreground">Žiadne behy kampane.</div>
        ) : (
          <div className="space-y-1">
            {history.map((job: any) => (
              <button
                key={job.id}
                type="button"
                onClick={() => { setHistoryJobId(job.id); setHistoryJobName(job.name || ""); }}
                className="w-full flex items-center justify-between text-xs border rounded px-3 py-1.5 hover-elevate active-elevate-2 text-left"
                data-testid={`history-job-${job.id}`}
              >
                <span className="font-medium truncate">{job.name}</span>
                <div className="flex items-center gap-3 shrink-0">
                  <span className={cn("px-1.5 py-0.5 rounded-full text-[10px]", job.status === "completed" ? "bg-green-100 text-green-700" : job.status === "failed" ? "bg-red-100 text-red-700" : "bg-yellow-100 text-yellow-700")}>{job.status}</span>
                  <span>{job.totalResults || 0} leadov</span>
                  <span>{new Date(job.createdAt).toLocaleDateString("sk-SK")}</span>
                  <ChevronRight className="h-3 w-3 text-muted-foreground" />
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    );
  };

  const COUNTRIES = [
    { code: "SK", flag: "🇸🇰", name: "Slovensko" },
    { code: "CZ", flag: "🇨🇿", name: "Česko" },
    { code: "HU", flag: "🇭🇺", name: "Maďarsko" },
    { code: "PL", flag: "🇵🇱", name: "Poľsko" },
    { code: "AT", flag: "🇦🇹", name: "Rakúsko" },
    { code: "DE", flag: "🇩🇪", name: "Nemecko" },
  ];

  return (
    <div className="space-y-4">
      <div className="flex gap-1 p-1 bg-muted/50 rounded-lg w-fit">
        {([
          { key: "dashboard" as const, label: "Dashboard", Icon: BarChart3 },
          { key: "search" as const, label: "Vyhľadávanie", Icon: Target },
          { key: "sources" as const, label: "Zdroje", Icon: Network },
          { key: "campaigns" as const, label: "Kampane", Icon: RefreshCw },
          { key: "templates" as const, label: "Šablóny", Icon: Layers },
          { key: "webhooks" as const, label: "Webhooky", Icon: Bell },
          { key: "entities" as const, label: "Entity Graf", Icon: Share2 },
          { key: "feedback" as const, label: "Učenie", Icon: Brain },
          { key: "lifecycle" as const, label: "Konverzie", Icon: TrendingUp },
        ] as const).map(tab => (
          <button
            key={tab.key}
            data-testid={`subtab-${tab.key}`}
            className={cn(
              "flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition-all",
              activeSubTab === tab.key ? "bg-background shadow-sm text-foreground" : "text-muted-foreground hover:text-foreground"
            )}
            onClick={() => setActiveSubTab(tab.key)}
          >
            <tab.Icon className="h-3.5 w-3.5" />{tab.label}
          </button>
        ))}
      </div>

      {activeSubTab === "dashboard" && (
        <div className="space-y-6">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <Card>
              <CardContent className="p-4">
                <div className="text-2xl font-bold" data-testid="stat-total-leads">{analytics?.totalLeads || 0}</div>
                <div className="text-xs text-muted-foreground">Celkom leadov</div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <div className="text-2xl font-bold text-green-600" data-testid="stat-assigned-leads">{analytics?.assignedLeads || 0}</div>
                <div className="text-xs text-muted-foreground">Priradených</div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <div className="text-2xl font-bold text-blue-600" data-testid="stat-avg-confidence">{analytics?.avgConfidence || 0}%</div>
                <div className="text-xs text-muted-foreground">Priemerná kvalita</div>
              </CardContent>
            </Card>
            <Card>
              <CardContent className="p-4">
                <div className="text-2xl font-bold text-violet-600" data-testid="stat-total-jobs">{analytics?.totalJobs || 0}</div>
                <div className="text-xs text-muted-foreground">Vyhľadávaní</div>
              </CardContent>
            </Card>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base">Leady podľa krajiny</CardTitle>
              </CardHeader>
              <CardContent>
                {analytics?.byCountry && Object.keys(analytics.byCountry).length > 0 ? (
                  <div className="space-y-2">
                    {Object.entries(analytics.byCountry).sort((a: any, b: any) => b[1] - a[1]).map(([country, count]: any) => (
                      <div key={country} className="flex items-center gap-2">
                        <span className="text-sm font-medium w-12">{country}</span>
                        <div className="flex-1 bg-muted rounded-full h-5 overflow-hidden">
                          <div className="bg-blue-500 h-full rounded-full transition-all" style={{ width: `${Math.min((count / (analytics.totalLeads || 1)) * 100, 100)}%` }} />
                        </div>
                        <span className="text-sm text-muted-foreground w-10 text-right">{count}</span>
                      </div>
                    ))}
                  </div>
                ) : <div className="text-sm text-muted-foreground py-4 text-center">Žiadne dáta</div>}
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base">Kvalita leadov</CardTitle>
              </CardHeader>
              <CardContent>
                {analytics?.byConfidenceTier ? (
                  <div className="space-y-2">
                    {Object.entries(analytics.byConfidenceTier).map(([tier, count]: any) => (
                      <div key={tier} className="flex items-center gap-2">
                        <span className="text-sm font-medium w-16">{tier}</span>
                        <div className="flex-1 bg-muted rounded-full h-5 overflow-hidden">
                          <div className={cn("h-full rounded-full transition-all", tier === "90+" ? "bg-green-500" : tier === "70-89" ? "bg-blue-500" : tier === "50-69" ? "bg-yellow-500" : "bg-gray-400")} style={{ width: `${Math.min((count / Math.max(analytics.totalLeads || 1, 1)) * 100, 100)}%` }} />
                        </div>
                        <span className="text-sm text-muted-foreground w-10 text-right">{count}</span>
                      </div>
                    ))}
                  </div>
                ) : <div className="text-sm text-muted-foreground py-4 text-center">Žiadne dáta</div>}
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base">Top 10 zdrojov</CardTitle>
              </CardHeader>
              <CardContent>
                {analytics?.topSources?.length > 0 ? (
                  <div className="space-y-1.5">
                    {analytics.topSources.map((s: any, i: number) => (
                      <div key={s.domain} className="flex items-center gap-2 text-sm">
                        <span className="text-muted-foreground w-5 text-right">{i + 1}.</span>
                        <span className="flex-1 truncate font-mono text-xs">{s.domain}</span>
                        <span className="text-muted-foreground">{s.count}</span>
                      </div>
                    ))}
                  </div>
                ) : <div className="text-sm text-muted-foreground py-4 text-center">Žiadne dáta</div>}
              </CardContent>
            </Card>

            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base">Leady v čase (posledných 30 dní)</CardTitle>
              </CardHeader>
              <CardContent>
                {analytics?.timeline?.length > 0 ? (
                  <div className="flex items-end gap-0.5 h-32">
                    {analytics.timeline.map((t: any) => {
                      const maxCount = Math.max(...analytics.timeline.map((x: any) => x.count));
                      const height = maxCount > 0 ? (t.count / maxCount) * 100 : 0;
                      return (
                        <div key={t.date} className="flex-1 flex flex-col items-center gap-0.5 group relative">
                          <div className="w-full bg-violet-500 rounded-t transition-all hover:bg-violet-600" style={{ height: `${Math.max(height, 2)}%` }} />
                          <div className="absolute -top-6 bg-popover border rounded px-1.5 py-0.5 text-[10px] shadow-sm opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap z-10">
                            {t.date}: {t.count}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                ) : <div className="text-sm text-muted-foreground py-4 text-center">Žiadne dáta</div>}
              </CardContent>
            </Card>
          </div>

          {analytics?.bySegment && Object.keys(analytics.bySegment).length > 0 && (
            <Card>
              <CardHeader className="pb-3">
                <CardTitle className="text-base">Leady podľa segmentu</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="flex flex-wrap gap-2">
                  {Object.entries(analytics.bySegment).sort((a: any, b: any) => b[1] - a[1]).slice(0, 15).map(([segment, count]: any) => (
                    <span key={segment} className="px-2 py-1 rounded-full bg-violet-100 dark:bg-violet-900/30 text-violet-700 dark:text-violet-300 text-xs">
                      {segment} ({count})
                    </span>
                  ))}
                </div>
              </CardContent>
            </Card>
          )}
        </div>
      )}

      {activeSubTab === "sources" && (
        <div className="space-y-6">
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base flex items-center gap-2">
                <Globe className="h-4 w-4" />
                Pridať zdroj
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                <div>
                  <label className="text-sm font-medium mb-1 block">URL</label>
                  <Input data-testid="input-source-url" placeholder="https://example.com" value={sourceForm.url} onChange={(e) => setSourceForm({ ...sourceForm, url: e.target.value })} />
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Názov</label>
                  <Input data-testid="input-source-name" placeholder="Názov zdroja" value={sourceForm.name} onChange={(e) => setSourceForm({ ...sourceForm, name: e.target.value })} />
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Typ</label>
                  <Select value={sourceForm.type} onValueChange={(v) => setSourceForm({ ...sourceForm, type: v })}>
                    <SelectTrigger data-testid="select-source-type"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="directory">Adresár</SelectItem>
                      <SelectItem value="registry">Register</SelectItem>
                      <SelectItem value="website">Webstránka</SelectItem>
                      <SelectItem value="portal">Portál</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                <div>
                  <label className="text-sm font-medium mb-1 block">Krajina</label>
                  <Select value={sourceForm.countryCode || "all"} onValueChange={(v) => setSourceForm({ ...sourceForm, countryCode: v === "all" ? "" : v })}>
                    <SelectTrigger data-testid="select-source-country"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">Všetky</SelectItem>
                      {COUNTRIES.map(c => <SelectItem key={c.code} value={c.code}>{c.flag} {c.name}</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Segment</label>
                  <Input data-testid="input-source-segment" placeholder="napr. nemocnice, kardiológia" value={sourceForm.segment} onChange={(e) => setSourceForm({ ...sourceForm, segment: e.target.value })} />
                </div>
                <div className="flex items-end">
                  <Button onClick={createSource} className="w-full" data-testid="button-create-source">
                    <Plus className="h-4 w-4 mr-2" />
                    Pridať zdroj
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base">Správa zdrojov ({leadSources.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {leadSources.length === 0 ? (
                <div className="text-center text-muted-foreground py-8">Žiadne zdroje. Pridajte nový alebo spustite vyhľadávanie — zdroje sa pridajú automaticky.</div>
              ) : (
                <div className="overflow-x-auto">
                  <div className="flex items-center gap-2 mb-3">
                    <Button variant="outline" size="sm" className="text-xs" data-testid="button-recalculate-scores" onClick={async () => {
                      await fetch("/api/lead-sources/recalculate-all", { method: "POST", credentials: "include" });
                      refetchSources();
                      toast({ title: "Skóre prepočítané" });
                    }}>
                      <BarChart3 className="h-3 w-3 mr-1" /> Prepočítať skóre
                    </Button>
                    <Button variant="outline" size="sm" className="text-xs" data-testid="button-export-sources" onClick={() => { window.open("/api/lead-sources/export", "_blank"); }}>
                      <Download className="h-3 w-3 mr-1" /> XLSX Export
                    </Button>
                  </div>
                  <table className="w-full text-sm">
                    <thead>
                      <tr className="border-b">
                        <th className="text-left py-2 px-2 font-medium">Názov</th>
                        <th className="text-left py-2 px-2 font-medium">URL</th>
                        <th className="text-left py-2 px-2 font-medium">Typ</th>
                        <th className="text-left py-2 px-2 font-medium">Krajina</th>
                        <th className="text-left py-2 px-2 font-medium">Skóre</th>
                        <th className="text-left py-2 px-2 font-medium">Úspešnosť</th>
                        <th className="text-left py-2 px-2 font-medium">Zoznam</th>
                        <th className="text-left py-2 px-2 font-medium">Status</th>
                        <th className="text-right py-2 px-2 font-medium">Akcie</th>
                      </tr>
                    </thead>
                    <tbody>
                      {leadSources.map((source: any) => (
                        <Fragment key={source.id}>
                        <tr data-testid={`source-row-${source.id}`} className="border-b hover:bg-accent/30">
                          <td className="py-2 px-2 font-medium">
                            <div className="flex items-center gap-1.5">
                              {source.name}
                              {source.isJsHeavy && <span className="text-[9px] bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 px-1 rounded" title="JS-heavy site">JS</span>}
                            </div>
                          </td>
                          <td className="py-2 px-2 text-xs font-mono truncate max-w-[200px]">
                            <a href={source.url} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline">{source.url}</a>
                          </td>
                          <td className="py-2 px-2">
                            <span className="text-xs px-1.5 py-0.5 rounded bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300">{source.type}</span>
                          </td>
                          <td className="py-2 px-2 text-xs">{source.countryCode || "-"}</td>
                          <td className="py-2 px-2">
                            <div className="flex items-center gap-1">
                              <div className="w-12 h-1.5 rounded-full bg-muted overflow-hidden">
                                <div className={cn("h-full rounded-full transition-all",
                                  (source.qualityScore || 50) >= 70 ? "bg-green-500" : (source.qualityScore || 50) >= 40 ? "bg-amber-500" : "bg-red-500"
                                )} style={{ width: `${source.qualityScore || 50}%` }} />
                              </div>
                              <span className="text-[10px] text-muted-foreground w-6">{source.qualityScore || 50}</span>
                            </div>
                          </td>
                          <td className="py-2 px-2">
                            <div className="flex items-center gap-1 text-xs">
                              <span className="text-green-600">{source.successCount || 0}</span>
                              <span className="text-muted-foreground">/</span>
                              <span className="text-red-600">{source.failCount || 0}</span>
                            </div>
                          </td>
                          <td className="py-2 px-2">
                            <Select value={source.listType || "none"} onValueChange={async (v) => {
                              await fetch(`/api/lead-sources/${source.id}/list-type`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ listType: v }) });
                              refetchSources();
                            }}>
                              <SelectTrigger className="h-6 w-24 text-[10px]" data-testid={`list-type-${source.id}`}>
                                <SelectValue />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="none">Žiadny</SelectItem>
                                <SelectItem value="whitelist">Whitelist</SelectItem>
                                <SelectItem value="blacklist">Blacklist</SelectItem>
                              </SelectContent>
                            </Select>
                          </td>
                          <td className="py-2 px-2">
                            <span className={cn("text-xs px-1.5 py-0.5 rounded",
                              source.status === "active" ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" :
                              source.listType === "blacklist" ? "bg-gray-900 text-white dark:bg-gray-100 dark:text-gray-900" :
                              "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400"
                            )}>
                              {source.status === "active" ? "Aktívny" : source.listType === "blacklist" ? "Blacklist" : "Blokovaný"}
                            </span>
                          </td>
                          <td className="py-2 px-2 text-right">
                            <div className="flex items-center gap-1 justify-end">
                              <Button size="sm" variant="outline" className="h-7 text-xs" data-testid={`edit-source-${source.id}`} onClick={() => setEditingSource({...source})}>
                                <Pencil className="h-3 w-3" />
                              </Button>
                              <Button size="sm" variant="outline" className="h-7 text-xs" data-testid={`toggle-source-${source.id}`} onClick={() => toggleSourceStatus(source)}>
                                {source.status === "active" ? "Blokovať" : "Aktivovať"}
                              </Button>
                              <Button size="sm" variant="ghost" className="h-7 text-xs text-red-600" data-testid={`delete-source-${source.id}`} onClick={() => deleteSource(source.id)}>
                                <Trash2 className="h-3 w-3" />
                              </Button>
                            </div>
                          </td>
                        </tr>
                        {editingSource?.id === source.id && (
                          <tr>
                            <td colSpan={7} className="py-2 px-2 bg-muted/30">
                              <div className="flex items-center gap-2">
                                <Input className="h-7 text-xs flex-1" value={editingSource.url} onChange={(e) => setEditingSource({...editingSource, url: e.target.value})} placeholder="URL" />
                                <Input className="h-7 text-xs flex-1" value={editingSource.name} onChange={(e) => setEditingSource({...editingSource, name: e.target.value})} placeholder="Názov" />
                                <Input className="h-7 text-xs w-20" value={editingSource.countryCode || ""} onChange={(e) => setEditingSource({...editingSource, countryCode: e.target.value})} placeholder="Krajina" />
                                <Input className="h-7 text-xs flex-1" value={editingSource.segment || ""} onChange={(e) => setEditingSource({...editingSource, segment: e.target.value})} placeholder="Segment" />
                                <Button size="sm" className="h-7 text-xs" data-testid={`save-source-${source.id}`} onClick={() => updateSource(editingSource)}>Uložiť</Button>
                                <Button size="sm" variant="ghost" className="h-7 text-xs" onClick={() => setEditingSource(null)}>Zrušiť</Button>
                              </div>
                            </td>
                          </tr>
                        )}
                        </Fragment>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base flex items-center gap-2">
                <Zap className="h-4 w-4 text-amber-500" />
                AI návrhy zdrojov
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
                <div>
                  <label className="text-sm font-medium mb-1 block">Modul</label>
                  <Select value={aiSourceFilter.targetModule} onValueChange={(v) => setAiSourceFilter({ ...aiSourceFilter, targetModule: v })}>
                    <SelectTrigger data-testid="select-ai-source-module"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="hospitals">Nemocnice</SelectItem>
                      <SelectItem value="clinics">Ambulancie</SelectItem>
                      <SelectItem value="collaborators">Spolupracovníci</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Krajina</label>
                  <Select value={aiSourceFilter.country || "all"} onValueChange={(v) => setAiSourceFilter({ ...aiSourceFilter, country: v === "all" ? "" : v })}>
                    <SelectTrigger data-testid="select-ai-source-country"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">Všetky</SelectItem>
                      {COUNTRIES.map(c => <SelectItem key={c.code} value={c.code}>{c.flag} {c.name}</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Segment</label>
                  <Input data-testid="input-ai-source-segment" placeholder="napr. gynekológia" value={aiSourceFilter.segment} onChange={(e) => setAiSourceFilter({ ...aiSourceFilter, segment: e.target.value })} />
                </div>
                <div className="flex items-end">
                  <Button onClick={getAiSourceSuggestions} className="w-full" disabled={aiSourceLoading} data-testid="button-ai-source-suggest">
                    {aiSourceLoading ? <Loader2 className="h-4 w-4 mr-2 animate-spin" /> : <Zap className="h-4 w-4 mr-2" />}
                    {aiSourceLoading ? "Hľadám..." : "Navrhnúť zdroje"}
                  </Button>
                </div>
              </div>

              {aiSourceSuggestions.length > 0 && (
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <p className="text-sm text-muted-foreground">Nájdených {aiSourceSuggestions.length} návrhov</p>
                    <Button size="sm" variant="outline" onClick={addAllSuggestedSources} data-testid="button-add-all-sources">
                      <Plus className="h-3 w-3 mr-1" />
                      Pridať všetky
                    </Button>
                  </div>
                  <div className="grid gap-2">
                    {aiSourceSuggestions.map((s: any, i: number) => (
                      <div key={i} className="flex items-start gap-3 p-3 rounded-lg border bg-card hover:bg-muted/30 transition-colors" data-testid={`ai-source-suggestion-${i}`}>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-1">
                            <span className="font-medium text-sm">{s.name}</span>
                            <span className={cn("text-[10px] px-1.5 py-0.5 rounded font-medium",
                              s.type === "registry" ? "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400" :
                              s.type === "directory" ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" :
                              s.type === "portal" ? "bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400" :
                              "bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-400"
                            )}>
                              {s.type === "registry" ? "Register" : s.type === "directory" ? "Adresár" : s.type === "portal" ? "Portál" : "Web"}
                            </span>
                            {s.countryCode && <span className="text-[10px] px-1.5 py-0.5 rounded bg-muted text-muted-foreground font-medium">{s.countryCode}</span>}
                          </div>
                          <a href={s.url} target="_blank" rel="noopener noreferrer" className="text-xs text-blue-600 dark:text-blue-400 hover:underline break-all">{s.url}</a>
                          {s.reason && <p className="text-xs text-muted-foreground mt-1">{s.reason}</p>}
                          {s.segment && <span className="text-[10px] text-muted-foreground">Segment: {s.segment}</span>}
                        </div>
                        <div className="flex gap-1 shrink-0">
                          <Button size="sm" variant="outline" className="h-7 text-xs" data-testid={`add-ai-source-${i}`} onClick={() => addSuggestedSource(s)}>
                            <Plus className="h-3 w-3 mr-1" />
                            Pridať
                          </Button>
                          <Button size="sm" variant="ghost" className="h-7 text-xs text-muted-foreground" onClick={() => setAiSourceSuggestions(prev => prev.filter((_, idx) => idx !== i))}>
                            <X className="h-3 w-3" />
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {activeSubTab === "campaigns" && (
        <div className="space-y-6">
          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base flex items-center gap-2">
                <Clock className="h-4 w-4" />
                Nová automatická kampaň
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                <div>
                  <label className="text-sm font-medium mb-1 block">Názov kampane</label>
                  <Input data-testid="input-campaign-name" placeholder="napr. Týždenné hľadanie gynekológov" value={campaignForm.name} onChange={(e) => setCampaignForm({ ...campaignForm, name: e.target.value })} />
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Cieľový modul</label>
                  <Select value={campaignForm.targetModule} onValueChange={(v) => setCampaignForm({ ...campaignForm, targetModule: v })}>
                    <SelectTrigger data-testid="select-campaign-module"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="hospitals">Nemocnice</SelectItem>
                      <SelectItem value="clinics">Ambulancie</SelectItem>
                      <SelectItem value="collaborators">Spolupracovníci</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Frekvencia</label>
                  <Select value={campaignForm.schedule} onValueChange={(v) => setCampaignForm({ ...campaignForm, schedule: v })}>
                    <SelectTrigger data-testid="select-campaign-schedule"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="daily">Denne</SelectItem>
                      <SelectItem value="weekly">Týždenne</SelectItem>
                      <SelectItem value="monthly">Mesačne</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
                <div>
                  <label className="text-sm font-medium mb-1 block">Krajina</label>
                  <Select value={campaignForm.country || "all"} onValueChange={(v) => setCampaignForm({ ...campaignForm, country: v === "all" ? "" : v })}>
                    <SelectTrigger data-testid="select-campaign-country"><SelectValue /></SelectTrigger>
                    <SelectContent>
                      <SelectItem value="all">Všetky</SelectItem>
                      {COUNTRIES.map(c => <SelectItem key={c.code} value={c.code}>{c.flag} {c.name}</SelectItem>)}
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Segment</label>
                  <Input data-testid="input-campaign-segment" placeholder="napr. kardiológia" value={campaignForm.segment} onChange={(e) => setCampaignForm({ ...campaignForm, segment: e.target.value })} />
                </div>
                <div>
                  <label className="text-sm font-medium mb-1 block">Lokalita</label>
                  <Input data-testid="input-campaign-location" placeholder="napr. Bratislava" value={campaignForm.location} onChange={(e) => setCampaignForm({ ...campaignForm, location: e.target.value })} />
                </div>
                <div className="flex items-end">
                  <Button onClick={createCampaign} className="w-full" data-testid="button-create-campaign">
                    <Plus className="h-4 w-4 mr-2" />
                    Vytvoriť kampaň
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          <Card>
            <CardHeader className="pb-3">
              <CardTitle className="text-base">Aktívne kampane ({leadCampaigns.length})</CardTitle>
            </CardHeader>
            <CardContent>
              {leadCampaigns.length === 0 ? (
                <div className="text-center text-muted-foreground py-8">Žiadne kampane. Vytvorte novú automatickú kampaň vyššie.</div>
              ) : (
                <div className="space-y-3">
                  {leadCampaigns.map((campaign: any) => (
                    <div key={campaign.id} data-testid={`campaign-row-${campaign.id}`} className="border rounded-lg p-4">
                      <div className="flex items-start justify-between">
                        <div>
                          <div className="font-medium text-sm flex items-center gap-2">
                            {campaign.name}
                            <span className={cn("text-[10px] px-1.5 py-0.5 rounded-full", campaign.isActive ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" : "bg-gray-100 text-gray-500 dark:bg-gray-800 dark:text-gray-400")}>
                              {campaign.isActive ? "Aktívna" : "Pozastavená"}
                            </span>
                          </div>
                          <div className="text-xs text-muted-foreground mt-1 flex flex-wrap gap-3">
                            <span>{campaign.targetModule}</span>
                            <span>{campaign.schedule === "daily" ? "Denne" : campaign.schedule === "weekly" ? "Týždenne" : "Mesačne"}</span>
                            {campaign.country && <span>{campaign.country}</span>}
                            {campaign.segment && <span>{campaign.segment}</span>}
                            {campaign.location && <span>{campaign.location}</span>}
                          </div>
                          <div className="text-xs text-muted-foreground mt-1.5 flex gap-4">
                            <span>Nájdených leadov: <strong>{campaign.totalLeadsFound || 0}</strong></span>
                            {campaign.lastRunAt && <span>Posledný beh: {new Date(campaign.lastRunAt).toLocaleDateString("sk-SK")}</span>}
                            {campaign.nextRunAt && (() => {
                              const nextDate = new Date(campaign.nextRunAt);
                              const now = new Date();
                              const diffMs = nextDate.getTime() - now.getTime();
                              const diffDays = Math.floor(diffMs / (1000 * 60 * 60 * 24));
                              const diffHours = Math.floor((diffMs % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
                              const countdown = diffMs <= 0 ? "čoskoro" : diffDays > 0 ? `za ${diffDays}d ${diffHours}h` : `za ${diffHours}h`;
                              return <span>Ďalší beh: <strong className={diffMs <= 0 ? "text-orange-600" : ""}>{countdown}</strong> ({nextDate.toLocaleDateString("sk-SK")})</span>;
                            })()}
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <Button size="sm" variant="outline" className="h-7 text-xs" data-testid={`toggle-campaign-${campaign.id}`} onClick={() => toggleCampaign(campaign)}>
                            {campaign.isActive ? "Pozastaviť" : "Aktivovať"}
                          </Button>
                          <Button size="sm" variant="outline" className="h-7 text-xs" data-testid={`history-campaign-${campaign.id}`} onClick={() => setHistoryCampaign({ id: campaign.id, name: campaign.name })}>
                            <ClipboardList className="h-3 w-3 mr-1" /> História
                          </Button>
                          <Button size="sm" variant="ghost" className="h-7 text-xs text-red-600" data-testid={`delete-campaign-${campaign.id}`} onClick={() => deleteCampaign(campaign.id)}>
                            <Trash2 className="h-3 w-3" />
                          </Button>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {activeSubTab === "search" && (
      <div className="space-y-6">

      <Card className="border-primary/20 bg-gradient-to-r from-primary/5 to-transparent">
        <CardHeader className="pb-2">
          <CardTitle className="text-base flex items-center gap-2"><Zap className="h-4 w-4 text-primary" /> Inteligentný cieľ vyhľadávania</CardTitle>
          <CardDescription>Popíšte čo hľadáte prirodzeným jazykom — systém sa naučí z histórie a odporučí najlepšie zdroje</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex gap-2">
            <Input data-testid="input-goal-text" placeholder="napr. nájdi ambulancie gynekológie v SK s emailom a telefónom" value={goalText} onChange={e => setGoalText(e.target.value)} className="flex-1" />
            <Button data-testid="button-parse-goal" disabled={!goalText.trim() || goalParsing} onClick={async () => {
              setGoalParsing(true);
              try {
                const resp = await fetch("/api/lead-intelligence/parse-goal", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ goal: goalText, country: searchForm.country || "SK" }) });
                const data = await resp.json();
                if (data.error) throw new Error(data.error);
                setParsedGoal(data);
                if (data.segment) {
                  const modMap: Record<string, string> = { hospitals: "hospitals", clinics: "clinics", ambulances: "hospitals", laboratories: "hospitals", pharmacies: "clinics", gynaecology: "hospitals", pediatrics: "hospitals", maternity: "hospitals" };
                  setSearchForm(f => ({ ...f, targetModule: (modMap[data.segment] || "collaborators") as any, country: data.country || f.country, keywords: data.keywords?.join(", ") || f.keywords, segment: data.segment }));
                }
                toast({ title: "Cieľ analyzovaný", description: `Segment: ${data.segment}, Kľúčové slová: ${data.keywords?.join(", ")}` });
              } catch (e: any) { toast({ title: "Chyba", description: e.message, variant: "destructive" }); }
              setGoalParsing(false);
            }}>{goalParsing ? <Loader2 className="h-4 w-4 animate-spin" /> : <Sparkles className="h-4 w-4" />} Analyzovať</Button>
          </div>
          {parsedGoal && (
            <div className="mt-3 grid grid-cols-2 md:grid-cols-4 gap-2">
              <div className="p-2 rounded-md bg-background border text-xs"><span className="text-muted-foreground">Segment:</span> <span className="font-medium">{parsedGoal.segment}</span></div>
              <div className="p-2 rounded-md bg-background border text-xs"><span className="text-muted-foreground">Krajina:</span> <span className="font-medium">{parsedGoal.country}</span></div>
              <div className="p-2 rounded-md bg-background border text-xs"><span className="text-muted-foreground">Intent:</span> <span className="font-medium">{parsedGoal.intent}</span></div>
              <div className="p-2 rounded-md bg-background border text-xs"><span className="text-muted-foreground">Outreach:</span> <span className="font-medium">{parsedGoal.outreachType || "—"}</span></div>
              {parsedGoal.requiredFields?.length > 0 && <div className="col-span-2 p-2 rounded-md bg-background border text-xs"><span className="text-muted-foreground">Povinné polia:</span> <span className="font-medium">{parsedGoal.requiredFields.join(", ")}</span></div>}
              {parsedGoal.learnedPreferences && <div className="col-span-2 p-2 rounded-md bg-green-50 dark:bg-green-950/20 border-green-200 dark:border-green-800 border text-xs"><Brain className="h-3 w-3 inline mr-1 text-green-600" /><span className="text-green-700 dark:text-green-400">Naučené preferencie: {parsedGoal.learnedPreferences.preferredRoles?.map((r: any) => r.role).join(", ")}</span></div>}
              {parsedGoal.recommendedSourceIds && <div className="col-span-2 p-2 rounded-md bg-blue-50 dark:bg-blue-950/20 border-blue-200 dark:border-blue-800 border text-xs"><Award className="h-3 w-3 inline mr-1 text-blue-600" /><span className="text-blue-700 dark:text-blue-400">Odporúčané zdroje ({parsedGoal.recommendedSourceIds.length}) na základe histórie</span></div>}
            </div>
          )}
        </CardContent>
      </Card>

      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">
        <div className="xl:col-span-4 space-y-4">
          <Card>
            <CardHeader className="pb-2">
              <div className="flex items-center justify-between">
                <CardTitle className="text-base flex items-center gap-2">
                  <Target className="h-4 w-4" />
                  Konfigurácia vyhľadávania
                </CardTitle>
                <span className="text-[10px] text-muted-foreground bg-muted px-2 py-0.5 rounded-full">
                  {searchForm.targetModule === "hospitals" ? "Nemocnice" : searchForm.targetModule === "clinics" ? "Ambulancie" : "Spolupracovníci"}
                  {searchForm.country ? ` · ${COUNTRIES.find(c => c.code === searchForm.country)?.flag || ""} ${searchForm.country}` : " · Všetky"}
                </span>
              </div>
            </CardHeader>
            <CardContent className="space-y-3">
              <div>
                <label className="text-xs font-medium mb-1 block text-muted-foreground uppercase tracking-wider">Názov vyhľadávania</label>
                <Input data-testid="input-search-name" placeholder="napr. Pôrodnice Wien + Graz" className="h-9" value={searchForm.name} onChange={(e) => setSearchForm({ ...searchForm, name: e.target.value })} />
              </div>

              <div className="rounded-lg border bg-muted/30 p-3 space-y-3">
                <span className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Cieľ vyhľadávania</span>
                <div>
                  <label className="text-xs font-medium mb-1.5 flex items-center gap-1.5 text-muted-foreground"><Building2 className="h-3 w-3" /> Cieľový modul</label>
                  <div className="grid grid-cols-3 gap-1.5">
                    {([
                      { key: "hospitals", label: "Nemocnice", icon: Building2 },
                      { key: "clinics", label: "Ambulancie", icon: Briefcase },
                      { key: "collaborators", label: "Spoluprac.", icon: Users },
                    ] as const).map(m => (
                      <button key={m.key} data-testid={`module-${m.key}`} className={cn("flex flex-col items-center gap-1 py-2 px-1.5 rounded-lg border text-[10px] font-medium transition-all",
                        searchForm.targetModule === m.key ? "border-primary bg-primary/10 text-primary shadow-sm" : "hover:border-primary/30 hover:bg-muted/50"
                      )} onClick={() => setSearchForm({ ...searchForm, targetModule: m.key as any })}>
                        <m.icon className="h-4 w-4" />
                        {m.label}
                      </button>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="text-xs font-medium mb-1.5 flex items-center gap-1.5 text-muted-foreground"><Globe className="h-3 w-3" /> Krajina</label>
                  <div className="grid grid-cols-3 gap-1">
                    <button data-testid="country-all" className={cn("py-1.5 px-2 rounded-md text-[10px] font-medium border transition-all",
                      !searchForm.country ? "border-primary bg-primary/10 text-primary" : "hover:border-primary/30"
                    )} onClick={() => setSearchForm({ ...searchForm, country: "" })}>
                      Všetky
                    </button>
                    {COUNTRIES.map(c => (
                      <button key={c.code} data-testid={`country-${c.code}`} className={cn("py-1.5 px-2 rounded-md text-[10px] font-medium border transition-all truncate",
                        searchForm.country === c.code ? "border-primary bg-primary/10 text-primary" : "hover:border-primary/30"
                      )} onClick={() => setSearchForm({ ...searchForm, country: c.code })}>
                        {c.flag} {c.code}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="rounded-lg border bg-muted/30 p-3 space-y-2.5">
                <span className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">Filtre vyhľadávania</span>
                <div>
                  <label className="text-xs font-medium mb-1 flex items-center gap-1.5 text-muted-foreground"><Layers className="h-3 w-3" /> Segment / Špecializácia</label>
                  <Input data-testid="input-segment" placeholder="napr. gynekológia, neonatológia, IVF" className="h-9" value={searchForm.segment} onChange={(e) => setSearchForm({ ...searchForm, segment: e.target.value })} />
                  <div className="flex flex-wrap gap-1 mt-1.5">
                    {(searchForm.targetModule === "hospitals"
                      ? ["gynekológia", "neonatológia", "onkológia", "hematológia", "transplantácie"]
                      : searchForm.targetModule === "clinics"
                      ? ["gynekológia", "pôrodníctvo", "pediatria", "IVF", "genetika"]
                      : ["distribútor", "farmaceut", "med. rep.", "lekár"]
                    ).map(tag => (
                      <button key={tag} className="text-[9px] px-1.5 py-0.5 rounded border border-dashed border-muted-foreground/30 text-muted-foreground hover:border-primary/50 hover:text-primary hover:bg-primary/5 transition-colors" onClick={() => setSearchForm(f => ({ ...f, segment: f.segment ? `${f.segment}, ${tag}` : tag }))}>
                        + {tag}
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="text-xs font-medium mb-1 flex items-center gap-1.5 text-muted-foreground"><MapPin className="h-3 w-3" /> Lokalita / Región</label>
                  <Input data-testid="input-location" placeholder={searchForm.country === "AT" ? "napr. Wien, Graz, Linz, Innsbruck" : searchForm.country === "CZ" ? "napr. Praha, Brno, Ostrava" : "napr. Bratislava, Košice"} className="h-9" value={searchForm.location} onChange={(e) => setSearchForm({ ...searchForm, location: e.target.value })} />
                  <div className="flex flex-wrap gap-1 mt-1.5">
                    {(searchForm.country === "AT"
                      ? ["Wien", "Graz", "Linz", "Salzburg", "Innsbruck", "Klagenfurt"]
                      : searchForm.country === "CZ"
                      ? ["Praha", "Brno", "Ostrava", "Plzeň", "Olomouc"]
                      : searchForm.country === "HU"
                      ? ["Budapest", "Debrecen", "Szeged", "Miskolc", "Pécs"]
                      : searchForm.country === "DE"
                      ? ["Berlin", "München", "Hamburg", "Frankfurt", "Köln"]
                      : searchForm.country === "IT"
                      ? ["Milano", "Roma", "Torino", "Bologna", "Firenze"]
                      : searchForm.country === "RO"
                      ? ["București", "Cluj-Napoca", "Timișoara", "Iași", "Constanța"]
                      : searchForm.country === "CH"
                      ? ["Zürich", "Bern", "Basel", "Genève", "Lausanne"]
                      : ["Bratislava", "Košice", "Žilina", "B. Bystrica", "Nitra", "Prešov", "Trnava"]
                    ).map(city => (
                      <button key={city} className="text-[9px] px-1.5 py-0.5 rounded border border-dashed border-muted-foreground/30 text-muted-foreground hover:border-primary/50 hover:text-primary hover:bg-primary/5 transition-colors" onClick={() => setSearchForm(f => ({ ...f, location: f.location ? `${f.location}, ${city}` : city }))}>
                        + {city}
                      </button>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="text-xs font-medium mb-1 flex items-center gap-1.5 text-muted-foreground"><Key className="h-3 w-3" /> Kľúčové slová</label>
                  <Input data-testid="input-keywords" placeholder={searchForm.country === "AT" ? "napr. Geburtshilfe, Stammzellen, Nabelschnur" : "napr. pôrodnica, kmeňové bunky"} className="h-9" value={searchForm.keywords} onChange={(e) => setSearchForm({ ...searchForm, keywords: e.target.value })} />
                  <div className="flex flex-wrap gap-1 mt-1.5">
                    {(searchForm.country === "AT" || searchForm.country === "DE" || searchForm.country === "CH"
                      ? ["Stammzellen", "Nabelschnurblut", "Geburtshilfe", "Pränataldiagnostik", "IVF-Zentrum", "Klinikum"]
                      : searchForm.country === "CZ"
                      ? ["kmenové buňky", "pupečníková krev", "porodnice", "gynekologie", "neonatologie"]
                      : searchForm.country === "HU"
                      ? ["őssejt", "köldökzsinórvér", "szülészet", "nőgyógyászat", "IVF"]
                      : ["kmeňové bunky", "pupočníková krv", "pôrodnica", "regeneratívna medicína", "transplantácia"]
                    ).map(kw => (
                      <button key={kw} className="text-[9px] px-1.5 py-0.5 rounded border border-dashed border-muted-foreground/30 text-muted-foreground hover:border-primary/50 hover:text-primary hover:bg-primary/5 transition-colors" onClick={() => setSearchForm(f => ({ ...f, keywords: f.keywords ? `${f.keywords}, ${kw}` : kw }))}>
                        + {kw}
                      </button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="pt-1 space-y-2">
                <button className="w-full flex items-center justify-between text-[10px] text-muted-foreground hover:text-foreground transition-colors py-1 px-1" onClick={() => setShowSearchParams(!showSearchParams)} data-testid="toggle-search-params">
                  <span className="flex items-center gap-1"><SlidersHorizontal className="h-3 w-3" /> Parametre vyhľadávania</span>
                  <span className="flex items-center gap-1">
                    {Object.entries(searchParams).some(([k, v]) => {
                      const meta = searchParamsMeta[k];
                      if (!meta) return false;
                      return v !== meta.rec;
                    }) && <span className="text-amber-600 font-medium">upravené</span>}
                    {showSearchParams ? <ChevronUp className="h-3 w-3" /> : <ChevronDown className="h-3 w-3" />}
                  </span>
                </button>
                {showSearchParams && (
                  <div className="rounded-lg border border-dashed border-primary/30 bg-primary/[0.02] p-3 space-y-3">
                    <div className="flex items-center justify-between">
                      <span className="text-[10px] font-semibold text-foreground/80">Konfigurácia pipeline</span>
                      <button className="text-[9px] text-primary hover:underline" onClick={() => setSearchParams({
                        queryCount: 40, googlePages: 6, retryThreshold: 100, maxPagesToScrape: 200, deepCrawlDirectories: 20,
                        deepCrawlLinksPerDir: 50, deepCrawlMaxSubpages: 150, paginationDepth: 15, contactPageDomains: 80,
                        domainExpansionTopN: 15, domainExpansionLinksPerDomain: 30, aiFirstPassPages: 40, aiPassBatchSize: 20,
                        enableCityQueries: true, enableDomainExpansion: true, enableRuleExtraction: true,
                      })} data-testid="reset-search-params">Obnoviť odporúčané</button>
                    </div>

                    {(["discovery", "scraping", "expansion", "ai"] as const).map(cat => (
                      <div key={cat}>
                        <span className="text-[9px] font-semibold uppercase tracking-wider text-muted-foreground block mb-1.5">
                          {cat === "discovery" ? "Vyhľadávanie" : cat === "scraping" ? "Scraping" : cat === "expansion" ? "Expanzia" : "AI Extrakcia"}
                        </span>
                        <div className="space-y-2">
                          {Object.entries(searchParamsMeta).filter(([, m]) => m.category === cat).map(([key, meta]) => {
                            const val = (searchParams as any)[key] as number;
                            const isOverRec = val > meta.rec;
                            const isUnderRec = val < meta.rec;
                            return (
                              <div key={key} className="space-y-0.5">
                                <div className="flex items-center justify-between">
                                  <span className="text-[10px] text-foreground/80">{meta.label}</span>
                                  <div className="flex items-center gap-1.5">
                                    {isOverRec && <span className="text-[8px] bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 px-1 py-0.5 rounded font-medium">nad odporúčanie</span>}
                                    {isUnderRec && <span className="text-[8px] bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 px-1 py-0.5 rounded font-medium">pod odporúčanie</span>}
                                    <span className={cn("text-[10px] font-mono font-bold tabular-nums min-w-[32px] text-right", isOverRec ? "text-amber-600" : isUnderRec ? "text-blue-600" : "text-foreground")}>{val}</span>
                                    <span className="text-[8px] text-muted-foreground">{meta.unit}</span>
                                  </div>
                                </div>
                                <div className="relative">
                                  <input
                                    type="range" min={meta.min} max={meta.max} value={val}
                                    onChange={e => setSearchParams(p => ({ ...p, [key]: parseInt(e.target.value) }))}
                                    className="w-full h-1.5 appearance-none bg-muted rounded-full cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:h-3.5 [&::-webkit-slider-thumb]:w-3.5 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-primary [&::-webkit-slider-thumb]:shadow-sm [&::-webkit-slider-thumb]:border-2 [&::-webkit-slider-thumb]:border-background"
                                    data-testid={`param-${key}`}
                                  />
                                  <div className="absolute top-0 left-0 h-1.5 rounded-full bg-primary/20 pointer-events-none" style={{ width: `${((meta.rec - meta.min) / (meta.max - meta.min)) * 100}%` }} />
                                </div>
                                <div className="flex justify-between text-[8px] text-muted-foreground">
                                  <span>{meta.min}</span>
                                  <span className="text-primary/60">odp. {meta.rec}</span>
                                  <span>{meta.max}</span>
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      </div>
                    ))}

                    <div className="border-t pt-2 space-y-1.5">
                      <span className="text-[9px] font-semibold uppercase tracking-wider text-muted-foreground block">Moduly</span>
                      {([
                        { key: "enableCityQueries", label: "Mestské dopyty", desc: "Automatický dopyt pre každé veľké mesto" },
                        { key: "enableDomainExpansion", label: "Domain expansion", desc: "Hĺbkové prehľadanie najbohatších domén" },
                        { key: "enableRuleExtraction", label: "Rule-based extrakcia", desc: "Regex extrakcia pred AI" },
                      ] as const).map(({ key, label, desc }) => (
                        <label key={key} className="flex items-start gap-2 cursor-pointer group" data-testid={`toggle-${key}`}>
                          <input type="checkbox" className="mt-0.5 rounded accent-primary" checked={(searchParams as any)[key]} onChange={e => setSearchParams(p => ({ ...p, [key]: e.target.checked }))} />
                          <div>
                            <span className="text-[10px] font-medium text-foreground/80 group-hover:text-foreground">{label}</span>
                            <span className="text-[9px] text-muted-foreground block">{desc}</span>
                          </div>
                        </label>
                      ))}
                    </div>

                    <div className="rounded-md bg-muted/50 p-2 text-[9px] text-muted-foreground">
                      <span className="font-medium text-foreground/70">Odhad trvania: </span>
                      {(() => {
                        const est = Math.round((searchParams.queryCount * searchParams.googlePages * 1.5 + searchParams.maxPagesToScrape * 0.5 + searchParams.deepCrawlMaxSubpages * 0.5 + searchParams.contactPageDomains * 0.3) / 60);
                        return est < 5 ? "~2-5 minút" : est < 15 ? `~${est} minút` : est < 60 ? `~${Math.round(est / 5) * 5} minút` : `~${Math.round(est / 60 * 10) / 10} hodín`;
                      })()}
                      {" | "}
                      <span className="font-medium text-foreground/70">Vyššie hodnoty = viac výsledkov, ale dlhší čas</span>
                    </div>
                  </div>
                )}

                <Button onClick={startSearch} className="w-full h-10" data-testid="button-start-search">
                  <Search className="h-4 w-4 mr-2" />
                  Spustiť vyhľadávanie
                </Button>
                <div className="grid grid-cols-2 gap-2">
                  <Button variant="outline" size="sm" className="w-full text-[11px]" data-testid="button-create-campaign-from-search" onClick={() => {
                    setCampaignForm({ name: searchForm.name || `Kampaň - ${searchForm.targetModule}`, targetModule: searchForm.targetModule, country: searchForm.country || "", segment: searchForm.segment || "", location: searchForm.location || "", keywords: searchForm.keywords || "", schedule: "weekly" });
                    setActiveSubTab("campaigns");
                  }}>
                    <RefreshCw className="h-3 w-3 mr-1" />
                    Kampaň
                  </Button>
                  <Button variant="ghost" size="sm" className="w-full text-[11px] text-muted-foreground" onClick={() => setSearchForm({ name: "", targetModule: searchForm.targetModule, country: searchForm.country, segment: "", location: "", keywords: "" })} data-testid="button-clear-search">
                    <X className="h-3 w-3 mr-1" />
                    Vyčistiť
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        <div className="xl:col-span-3 space-y-4">
          <Card className="border-primary/20 bg-gradient-to-b from-primary/[0.03] to-transparent">
            <CardHeader className="pb-2">
              <div className="flex items-center justify-between">
                <CardTitle className="text-sm flex items-center gap-2">
                  <Brain className="h-4 w-4 text-primary" />
                  AI Stratég
                </CardTitle>
                {aiSuggestions.length > 0 && (
                  <span className="text-[10px] bg-primary/10 text-primary px-2 py-0.5 rounded-full font-medium">{aiSuggestions.length} scenárov</span>
                )}
              </div>
              <p className="text-[11px] text-muted-foreground">Hĺbková analýza medzier, učenie z histórie, prioritizácia podľa ROI potenciálu</p>
            </CardHeader>
            <CardContent className="space-y-3">
              <div>
                <span className="text-[10px] text-muted-foreground font-medium block mb-1.5">Režim analýzy</span>
                <div className="flex gap-1.5">
                  {(["quick", "standard", "deep"] as const).map(d => (
                    <button key={d} data-testid={`depth-${d}`} className={cn("flex-1 py-2 px-2 rounded-lg text-[10px] font-medium border transition-all",
                      aiSourceFilter.depth === d ? "border-primary bg-primary/10 text-primary shadow-sm" : "border-border hover:border-primary/40"
                    )} onClick={() => setAiSourceFilter((f: any) => ({ ...f, depth: d }))}>
                      <div className="flex flex-col items-center gap-0.5">
                        {d === "quick" ? <Sparkles className="h-3.5 w-3.5" /> : d === "standard" ? <Brain className="h-3.5 w-3.5" /> : <Network className="h-3.5 w-3.5" />}
                        {d === "quick" ? "Rýchly" : d === "standard" ? "Štandardný" : "Hĺbkový"}
                      </div>
                      <span className="block text-[9px] text-muted-foreground font-normal mt-0.5">{d === "quick" ? "3 scenáre" : d === "standard" ? "6 scenárov" : "10+ scenárov"}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="rounded-lg border border-dashed border-primary/20 bg-primary/[0.02] p-2.5">
                <div className="flex items-start gap-2 text-[10px] text-muted-foreground">
                  <Info className="h-3.5 w-3.5 mt-0.5 shrink-0 text-primary/60" />
                  <div>
                    <span className="font-medium text-foreground/80">AI analyzuje:</span> existujúce dáta v databáze, históriu úspešných/neúspešných vyhľadávaní, aktívne zdroje, a identifikuje medzery v pokrytí — mestá, regióny a segmenty kde ešte nemáte záznamy.
                  </div>
                </div>
              </div>

              <Button
                className="w-full h-10"
                variant="default"
                onClick={() => {
                  setAiSuggesting(true);
                  setAiSuggestions([]);
                  setSelectedSuggestions([]);
                  fetch("/api/lead-search/ai-suggest", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include",
                    body: JSON.stringify({ targetModule: searchForm.targetModule, country: searchForm.country, depth: aiSourceFilter.depth || "standard" })
                  }).then(r => r.json()).then(data => { setAiSuggestions(data.suggestions || []); setAiSuggesting(false); })
                  .catch(() => { toast({ title: "Chyba pri generovaní návrhov", variant: "destructive" }); setAiSuggesting(false); });
                }}
                disabled={aiSuggesting}
                data-testid="button-ai-suggest"
              >
                {aiSuggesting ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Sparkles className="h-4 w-4 mr-2" />}
                {aiSuggesting ? "AI analyzuje medzery..." : "Spustiť AI analýzu"}
              </Button>

              {aiSuggestions.length > 0 && (
                <div className="space-y-2">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-[9px] text-muted-foreground">
                        {aiSuggestions.filter((s: any) => s.priority === "high").length > 0 && (
                          <span className="text-red-600 font-medium">{aiSuggestions.filter((s: any) => s.priority === "high").length} vysoká</span>
                        )}
                        {aiSuggestions.filter((s: any) => s.priority === "medium").length > 0 && (
                          <span className="text-amber-600 font-medium ml-1">{aiSuggestions.filter((s: any) => s.priority === "medium").length} stredná</span>
                        )}
                      </span>
                    </div>
                    {selectedSuggestions.length > 0 && (
                      <Button size="sm" variant="default" className="h-6 text-[10px] px-2" onClick={applySelectedSuggestions} data-testid="button-apply-suggestions">
                        <Check className="h-3 w-3 mr-1" />
                        Použiť {selectedSuggestions.length}
                      </Button>
                    )}
                  </div>
                  <div className="space-y-1.5 max-h-[500px] overflow-y-auto pr-1">
                    {aiSuggestions.map((s: any, i: number) => (
                      <div key={i} className={cn("rounded-lg border p-2.5 cursor-pointer transition-all",
                        selectedSuggestions.includes(i) ? "border-primary bg-primary/5 shadow-sm" : "hover:border-primary/30",
                        s.priority === "high" && !selectedSuggestions.includes(i) ? "border-l-2 border-l-red-400" : ""
                      )} data-testid={`ai-suggestion-${i}`} onClick={() => toggleSuggestion(i)}>
                        <div className="flex items-start gap-2">
                          <input type="checkbox" className="mt-0.5 rounded border-muted-foreground/40 accent-primary" checked={selectedSuggestions.includes(i)} onChange={() => toggleSuggestion(i)} />
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between gap-1 mb-0.5">
                              <span className="text-xs font-semibold leading-tight">{s.name}</span>
                              <div className="flex items-center gap-1 shrink-0">
                                {s.priority && (
                                  <span className={cn("text-[9px] px-1.5 py-0.5 rounded-full font-medium",
                                    s.priority === "high" ? "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400" :
                                    s.priority === "medium" ? "bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400" :
                                    "bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400"
                                  )}>{s.priority === "high" ? "Vysoká" : s.priority === "medium" ? "Stredná" : "Nízka"}</span>
                                )}
                                <button className="text-primary hover:bg-primary/10 rounded p-0.5 transition-colors" onClick={(e) => { e.stopPropagation(); applySingleSuggestion(s); }} data-testid={`apply-suggestion-${i}`} title="Použiť tento scenár">
                                  <ArrowRight className="h-3.5 w-3.5" />
                                </button>
                              </div>
                            </div>
                            {s.reason && <p className="text-[10px] text-muted-foreground leading-snug mb-1.5">{s.reason}</p>}
                            <div className="flex flex-wrap gap-1">
                              {s.segment && (
                                <button className="inline-flex items-center gap-0.5 bg-violet-50 dark:bg-violet-900/20 text-violet-700 dark:text-violet-300 px-1.5 py-0.5 rounded text-[9px] font-medium hover:bg-violet-100 dark:hover:bg-violet-800/30 transition-colors border border-violet-200/50 dark:border-violet-700/30" onClick={(e) => { e.stopPropagation(); setSearchForm(f => ({ ...f, segment: s.segment })); }} data-testid={`use-segment-${i}`}>
                                  <Layers className="h-2.5 w-2.5" /> {s.segment}
                                </button>
                              )}
                              {s.location && (
                                <button className="inline-flex items-center gap-0.5 bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-300 px-1.5 py-0.5 rounded text-[9px] font-medium hover:bg-blue-100 dark:hover:bg-blue-800/30 transition-colors border border-blue-200/50 dark:border-blue-700/30" onClick={(e) => { e.stopPropagation(); setSearchForm(f => ({ ...f, location: s.location })); }} data-testid={`use-location-${i}`}>
                                  <MapPin className="h-2.5 w-2.5" /> {s.location}
                                </button>
                              )}
                              {s.keywords && (
                                <button className="inline-flex items-center gap-0.5 bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-300 px-1.5 py-0.5 rounded text-[9px] font-medium hover:bg-amber-100 dark:hover:bg-amber-800/30 transition-colors border border-amber-200/50 dark:border-amber-700/30" onClick={(e) => { e.stopPropagation(); setSearchForm(f => ({ ...f, keywords: s.keywords })); }} data-testid={`use-keywords-${i}`}>
                                  <Key className="h-2.5 w-2.5" /> {s.keywords}
                                </button>
                              )}
                            </div>
                            {(s.estimatedResults || s.searchDepth) && (
                              <div className="flex items-center gap-3 mt-1.5 text-[9px] text-muted-foreground">
                                {s.estimatedResults && <span className="flex items-center gap-0.5"><Target className="h-2.5 w-2.5" /> ~{s.estimatedResults} výsledkov</span>}
                                {s.searchDepth && <span className="flex items-center gap-0.5"><Filter className="h-2.5 w-2.5" /> {s.searchDepth === "broad" ? "Široký záber" : "Cielený záber"}</span>}
                              </div>
                            )}
                            {s.relatedSegments && s.relatedSegments.length > 0 && (
                              <div className="flex flex-wrap gap-1 mt-1.5">
                                <span className="text-[8px] text-muted-foreground/70">Súvisiace:</span>
                                {s.relatedSegments.map((rs: string, ri: number) => (
                                  <button key={ri} className="text-[8px] text-muted-foreground bg-muted/60 hover:bg-muted px-1.5 py-0.5 rounded transition-colors" onClick={(e) => { e.stopPropagation(); setSearchForm(f => ({ ...f, segment: rs })); }}>
                                    {rs}
                                  </button>
                                ))}
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>

        <Card className="xl:col-span-5">
          <CardHeader className="pb-3">
            <CardTitle className="text-base flex items-center gap-2"><Clock className="h-4 w-4" /> História vyhľadávaní</CardTitle>
          </CardHeader>
          <CardContent>
            {jobs.length === 0 ? (
              <div className="text-center text-muted-foreground py-8">
                Žiadne vyhľadávania. Vytvorte nové vyhľadávanie vľavo.
              </div>
            ) : (
              <div className="space-y-2 max-h-[300px] overflow-y-auto">
                {jobs.map((job: any) => (
                  <div
                    key={job.id}
                    data-testid={`job-row-${job.id}`}
                    className={`flex items-center justify-between p-3 rounded-lg border cursor-pointer transition-colors ${
                      selectedJobId === job.id ? "bg-primary/10 border-primary" : "hover:bg-accent/50"
                    }`}
                    onClick={() => setSelectedJobId(job.id)}
                  >
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-sm truncate">{job.name}</div>
                      <div className="text-xs text-muted-foreground flex items-center gap-2 mt-0.5">
                        <span className={`inline-flex items-center gap-1 px-1.5 py-0.5 rounded-full text-[10px] font-medium ${
                          job.status === "completed" ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" :
                          job.status === "running" ? "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400" :
                          job.status === "failed" ? "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400" :
                          job.status === "cancelled" ? "bg-orange-100 text-orange-700 dark:bg-orange-900/30 dark:text-orange-400" :
                          "bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-400"
                        }`}>
                          {job.status === "running" && <Loader2 className="h-3 w-3 animate-spin" />}
                          {job.status === "completed" && <CheckCircle2 className="h-3 w-3" />}
                          {job.status === "failed" && <XCircle className="h-3 w-3" />}
                          {job.status === "cancelled" && <Square className="h-3 w-3" />}
                          {job.status === "cancelled" ? "zastavený" : job.status}
                        </span>
                        <span>{job.targetModule}</span>
                        <span>{job.totalResults || 0} výsledkov</span>
                        <span>{job.assignedResults || 0} priradených</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>

      <Sheet open={!!selectedJobId} onOpenChange={(o) => { if (!o) setSelectedJobId(null); }}>
        <SheetContent side="right" className="w-screen sm:max-w-none sm:w-[95vw] overflow-y-auto p-0">
          <div className="p-6">
        <Card>
          <CardHeader className="pb-3">
            <div className="flex items-center justify-between">
              <CardTitle className="text-base flex items-center gap-2">
                Výsledky: {selectedJob?.name}
                {selectedJob?.status === "running" && <Loader2 className="h-4 w-4 animate-spin" />}
                {selectedJob?.status === "running" && (
                  <Button variant="destructive" size="sm" className="h-7 text-xs ml-2" disabled={stoppingJob} data-testid="button-stop-search" onClick={async () => {
                    setStoppingJob(true);
                    try {
                      await fetch(`/api/lead-search/jobs/${selectedJobId}/stop`, { method: "POST", credentials: "include" });
                      toast({ title: "Vyhľadávanie zastavené" });
                      refetchJobs();
                      refetchResults();
                    } catch { toast({ title: "Chyba pri zastavení", variant: "destructive" }); }
                    setStoppingJob(false);
                  }}>
                    {stoppingJob ? <Loader2 className="h-3 w-3 animate-spin mr-1" /> : <XCircle className="h-3 w-3 mr-1" />}
                    Zastaviť
                  </Button>
                )}
              </CardTitle>
              <div className="flex items-center gap-2">
                {results.length > 0 && (
                  <>
                    <div className="flex gap-1 text-[10px]">
                      {["all", "new", "approved", "rejected", "merged"].map(f => (
                        <button key={f} data-testid={`filter-${f}`} className={cn("px-2 py-1 rounded-md border transition-all",
                          reviewFilter === f ? "border-primary bg-primary/10 text-primary font-medium" : "hover:border-primary/30"
                        )} onClick={() => setReviewFilter(f)}>
                          {f === "all" ? "Všetky" : f === "new" ? "Nové" : f === "approved" ? "Schválené" : f === "rejected" ? "Zamietnuté" : "Zlúčené"}
                          <span className="ml-1 text-muted-foreground">({results.filter((r: any) => f === "all" || r.status === f).length})</span>
                        </button>
                      ))}
                    </div>
                    <Button variant="outline" size="sm" className="text-xs h-7" data-testid="button-export-results" onClick={() => window.open(`/api/search-results/export/${selectedJob?.id}`, "_blank")}>
                      <Download className="h-3 w-3 mr-1" /> XLSX
                    </Button>
                    <Button variant="outline" size="sm" className="text-xs h-7" data-testid="button-normalize-phones" onClick={async () => {
                      try {
                        const resp = await fetch("/api/lead-search/normalize-phones", { method: "POST", credentials: "include" });
                        const data = await resp.json();
                        if (data.success) {
                          toast({ title: `Normalizácia dokončená`, description: `${data.updated} čísel opravených, ${data.skipped} už bolo v poriadku` });
                          await refetchResults();
                        } else {
                          toast({ title: "Chyba", description: data.error, variant: "destructive" });
                        }
                      } catch (e: any) {
                        toast({ title: "Chyba", description: e.message, variant: "destructive" });
                      }
                    }}>
                      <Phone className="h-3 w-3 mr-1" /> Normalizovať čísla
                    </Button>
                    {results.filter((r: any) => r.status === "new").length > 0 && (
                      <div className="flex gap-1">
                        <Button variant="outline" size="sm" className="text-xs h-7 text-green-600 border-green-200" data-testid="button-bulk-approve" onClick={async () => {
                          const ids = results.filter((r: any) => r.status === "new").map((r: any) => r.id);
                          await fetch("/api/search-results/bulk-review", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ ids, status: "approved" }) });
                          await refetchResults();
                          toast({ title: `${ids.length} schválených` });
                        }}>
                          <Check className="h-3 w-3 mr-1" /> Schváliť všetky
                        </Button>
                      </div>
                    )}
                  </>
                )}
              </div>
            </div>
          </CardHeader>
          <CardContent>
            {results.length === 0 ? (
              <div className="text-center text-muted-foreground py-8">
                {selectedJob?.status === "running" ? "Vyhľadávanie prebieha..." : "Žiadne výsledky"}
              </div>
            ) : (
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b">
                      <th className="text-left py-2 px-2 font-medium">Názov</th>
                      <th className="text-left py-2 px-2 font-medium">Kontakt</th>
                      <th className="text-left py-2 px-2 font-medium">Email</th>
                      <th className="text-left py-2 px-2 font-medium">Telefón</th>
                      <th className="text-left py-2 px-2 font-medium">Mesto</th>
                      <th className="text-left py-2 px-2 font-medium">Skóre</th>
                      <th className="text-left py-2 px-2 font-medium">Status</th>
                      <th className="text-right py-2 px-2 font-medium">Akcie</th>
                    </tr>
                  </thead>
                  <tbody>
                    {results.filter((r: any) => reviewFilter === "all" || r.status === reviewFilter).map((r: any) => (
                      <tr key={r.id} data-testid={`result-row-${r.id}`} className="border-b hover:bg-accent/30">
                        <td className="py-2 px-2">
                          <div className="font-medium">{r.companyName || "-"}</div>
                          {r.website && (
                            <a href={r.website} target="_blank" rel="noopener noreferrer" className="text-xs text-blue-600 hover:underline">
                              {r.website}
                            </a>
                          )}
                        </td>
                        <td className="py-2 px-2 text-xs">{r.contactPerson || "-"}</td>
                        <td className="py-2 px-2 text-xs">{r.email || "-"}</td>
                        <td className="py-2 px-2 text-xs">{r.phone || "-"}</td>
                        <td className="py-2 px-2 text-xs">{r.city || "-"} {r.countryCode || ""}</td>
                        <td className="py-2 px-2">
                          <span className={`text-xs font-medium px-1.5 py-0.5 rounded ${
                            (r.confidenceScore || 0) >= 70 ? "bg-green-100 text-green-700" :
                            (r.confidenceScore || 0) >= 40 ? "bg-yellow-100 text-yellow-700" :
                            "bg-gray-100 text-gray-700"
                          }`}>
                            {r.confidenceScore || 0}%
                          </span>
                        </td>
                        <td className="py-2 px-2">
                          <span className={cn("text-xs px-1.5 py-0.5 rounded",
                            r.status === "approved" ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" :
                            r.status === "rejected" ? "bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400" :
                            r.status === "merged" ? "bg-violet-100 text-violet-700 dark:bg-violet-900/30 dark:text-violet-400" :
                            r.status === "assigned" ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" :
                            r.status === "skipped" ? "bg-gray-100 text-gray-500" :
                            "bg-blue-100 text-blue-700"
                          )}>
                            {r.status === "approved" ? "Schválený" : r.status === "rejected" ? "Zamietnutý" : r.status === "merged" ? "Zlúčený" : r.status === "assigned" ? "Priradený" : r.status === "skipped" ? "Preskočený" : "Nový"}
                          </span>
                        </td>
                        <td className="py-2 px-2 text-right">
                          <div className="flex items-center gap-1 justify-end">
                            {(r.status === "new" || r.status === "approved") && (
                              <>
                                <Button size="sm" variant="outline" className="h-6 text-[10px] px-1.5" data-testid={`preview-result-${r.id}`} onClick={() => {
                                  setPreviewResult(r);
                                  setExistingMatches([]);
                                  setSelectedMatch(null);
                                  setSelectedChanges({});
                                  setAssignModule(selectedJob?.targetModule || "hospitals");
                                  const raw = r.rawData || {};
                                  const allFields: Record<string, boolean> = {};
                                  if (r.companyName) allFields["companyName"] = true;
                                  if (r.contactPerson || raw.contact_person) allFields["contactPerson"] = true;
                                  if (r.email || raw.email) allFields["email"] = true;
                                  if (r.phone || raw.phone) allFields["phone"] = true;
                                  if (r.website || raw.website) allFields["website"] = true;
                                  if (r.address || raw.address) allFields["address"] = true;
                                  if (r.city || raw.city) allFields["city"] = true;
                                  if (r.countryCode) allFields["countryCode"] = true;
                                  if (raw.postal_code) allFields["postalCode"] = true;
                                  if (raw.region || raw.department) allFields["region"] = true;
                                  if (raw.doctor_title) allFields["doctorTitle"] = true;
                                  if (raw.doctor_first_name) allFields["doctorFirstName"] = true;
                                  if (raw.doctor_last_name) allFields["doctorLastName"] = true;
                                  if (r.specialization || raw.specialization) allFields["specialization"] = true;
                                  if (raw.notes) allFields["notes"] = true;
                                  if (raw.mobile) allFields["mobile"] = true;
                                  if (raw.company_name || raw.full_name) allFields["fullName"] = true;
                                  if (raw.collaborator_type) allFields["collaboratorType"] = true;
                                  if (raw.titleBefore) allFields["titleBefore"] = true;
                                  if (raw.titleAfter) allFields["titleAfter"] = true;
                                  setSelectedFields(allFields);
                                  setMatchLoading(true);
                                  fetch(`/api/lead-search/results/${r.id}/match`, { credentials: "include" })
                                    .then(resp => resp.ok ? resp.json() : { matches: [] })
                                    .then(data => { setExistingMatches(data.matches || []); setMatchLoading(false); })
                                    .catch(() => setMatchLoading(false));
                                }}>
                                  <Eye className="h-3 w-3" />
                                </Button>
                                {r.status === "new" && (
                                  <Button size="sm" variant="outline" className="h-6 text-[10px] px-1.5 text-green-600 border-green-200 hover:bg-green-50" data-testid={`approve-result-${r.id}`} onClick={async () => {
                                    await fetch(`/api/search-results/${r.id}/review`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ status: "approved" }) });
                                    await refetchResults();
                                  }}>
                                    <Check className="h-3 w-3" />
                                  </Button>
                                )}
                                {r.status === "new" && (
                                  <Button size="sm" variant="outline" className="h-6 text-[10px] px-1.5 text-red-600 border-red-200 hover:bg-red-50" data-testid={`reject-result-${r.id}`} onClick={async () => {
                                    await fetch(`/api/search-results/${r.id}/review`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ status: "rejected" }) });
                                    await refetchResults();
                                  }}>
                                    <X className="h-3 w-3" />
                                  </Button>
                                )}
                                {(r.status === "new" || r.status === "approved") && (
                                  <Button size="sm" variant="default" className="h-6 text-[10px] px-2" data-testid={`merge-result-${r.id}`} onClick={async () => {
                                    const resp = await fetch(`/api/search-results/${r.id}/merge`, { method: "POST", credentials: "include" });
                                    const data = await resp.json();
                                    if (data.success) {
                                      toast({ title: "Zlúčený do CRM", description: data.mergedTo });
                                      await refetchResults();
                                    }
                                  }}>
                                    CRM
                                  </Button>
                                )}
                              </>
                            )}
                            {r.status === "merged" && (
                              <span className="text-[10px] text-violet-600 font-medium flex items-center gap-0.5">
                                <CheckCircle2 className="h-3 w-3" /> Zlúčený
                              </span>
                            )}
                            {r.status === "rejected" && (
                              <Button size="sm" variant="ghost" className="h-6 text-[10px] px-1.5" data-testid={`restore-result-${r.id}`} onClick={async () => {
                                await fetch(`/api/search-results/${r.id}/review`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ status: "new" }) });
                                await refetchResults();
                              }}>
                                Obnoviť
                              </Button>
                            )}
                            <div className="flex gap-0.5 ml-1 border-l pl-1">
                              <Button size="sm" variant="ghost" className="h-5 w-5 p-0 text-green-600 hover:bg-green-50" data-testid={`feedback-good-${r.id}`} title="Správny kontakt" onClick={async () => {
                                await fetch("/api/lead-feedback", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ resultId: r.id, feedbackType: "correct_contact", segment: r.segment }) });
                                toast({ title: "Spätná väzba", description: "Označené ako správny kontakt" });
                              }}><ThumbsUp className="h-3 w-3" /></Button>
                              <Button size="sm" variant="ghost" className="h-5 w-5 p-0 text-red-600 hover:bg-red-50" data-testid={`feedback-bad-${r.id}`} title="Nesprávny kontakt" onClick={async () => {
                                await fetch("/api/lead-feedback", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ resultId: r.id, feedbackType: "incorrect_contact", segment: r.segment }) });
                                toast({ title: "Spätná väzba", description: "Označené ako nesprávny kontakt" });
                              }}><ThumbsDown className="h-3 w-3" /></Button>
                            </div>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </CardContent>
        </Card>
          </div>
        </SheetContent>
      </Sheet>

      <Dialog open={!!previewResult} onOpenChange={(open) => !open && setPreviewResult(null)}>
        <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle className="flex items-center gap-2">
              <Eye className="h-5 w-5" />
              Náhľad kontaktu
            </DialogTitle>
            <DialogDescription>
              Vyberte polia a cieľový modul pred uložením
            </DialogDescription>
          </DialogHeader>
          {previewResult && (() => {
            const raw = previewResult.rawData || {};
            const fieldDefs: { key: string; label: string; value: string }[] = [
              { key: "companyName", label: "Názov", value: previewResult.companyName || "" },
              { key: "fullName", label: "Plný názov", value: raw.company_name || raw.full_name || "" },
              { key: "contactPerson", label: "Kontaktná osoba", value: previewResult.contactPerson || raw.contact_person || "" },
              { key: "doctorTitle", label: "Titul", value: raw.doctor_title || raw.titleBefore || "" },
              { key: "doctorFirstName", label: "Meno", value: raw.doctor_first_name || "" },
              { key: "doctorLastName", label: "Priezvisko", value: raw.doctor_last_name || "" },
              { key: "titleAfter", label: "Titul za menom", value: raw.titleAfter || "" },
              { key: "specialization", label: "Špecializácia", value: previewResult.specialization || raw.specialization || "" },
              { key: "collaboratorType", label: "Typ spolupráce", value: raw.collaborator_type || "" },
              { key: "address", label: "Adresa", value: previewResult.address || raw.address || "" },
              { key: "city", label: "Mesto", value: previewResult.city || raw.city || "" },
              { key: "postalCode", label: "PSČ", value: raw.postal_code || "" },
              { key: "region", label: "Oblasť/Región", value: raw.region || raw.department || "" },
              { key: "countryCode", label: "Krajina", value: previewResult.countryCode || "" },
              { key: "email", label: "Email", value: previewResult.email || raw.email || "" },
              { key: "phone", label: "Telefón", value: previewResult.phone || raw.phone || "" },
              { key: "mobile", label: "Mobil", value: raw.mobile || "" },
              { key: "website", label: "Web", value: previewResult.website || raw.website || "" },
              { key: "notes", label: "Poznámky", value: raw.notes || "" },
            ].filter(f => f.value);
            const selectedCount = fieldDefs.filter(f => selectedFields[f.key]).length;
            return (
              <div className="space-y-4">
                <div className="flex items-center justify-between">
                  <div className="text-base font-semibold" data-testid="preview-company-name">
                    {previewResult.companyName || previewResult.contactPerson || "-"}
                  </div>
                  <span className={`text-xs font-medium px-2 py-0.5 rounded ${
                    (previewResult.confidenceScore || 0) >= 70 ? "bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400" :
                    (previewResult.confidenceScore || 0) >= 40 ? "bg-yellow-100 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-400" :
                    "bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-400"
                  }`}>
                    Spoľahlivosť: {previewResult.confidenceScore || 0}%
                  </span>
                </div>

                <div className="border rounded-lg p-4 space-y-3">
                  <div className="flex items-center justify-between">
                    <div className="text-xs font-semibold text-muted-foreground uppercase tracking-wide flex items-center gap-1.5">
                      <ClipboardList className="h-3.5 w-3.5" /> Údaje na uloženie ({selectedCount}/{fieldDefs.length})
                    </div>
                    <div className="flex gap-1">
                      <button className="text-[10px] text-blue-600 hover:underline" data-testid="button-select-all-fields" onClick={() => {
                        const all: Record<string, boolean> = {};
                        fieldDefs.forEach(f => all[f.key] = true);
                        setSelectedFields(all);
                      }}>Vybrať všetky</button>
                      <span className="text-muted-foreground text-[10px]">|</span>
                      <button className="text-[10px] text-blue-600 hover:underline" data-testid="button-deselect-all-fields" onClick={() => setSelectedFields({})}>Zrušiť všetky</button>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                    {fieldDefs.map(f => (
                      <label key={f.key} className={cn("flex items-start gap-2 py-1.5 px-2 rounded cursor-pointer transition-colors text-sm", selectedFields[f.key] ? "bg-primary/5" : "opacity-50")} data-testid={`field-${f.key}`}>
                        <input type="checkbox" className="mt-1 rounded" checked={!!selectedFields[f.key]} onChange={(e) => setSelectedFields(prev => ({ ...prev, [f.key]: e.target.checked }))} />
                        <div className="flex-1 min-w-0">
                          <span className="text-muted-foreground text-xs">{f.label}:</span>
                          <div className={cn("font-medium truncate", f.key === "email" ? "text-blue-600" : "")}>{f.value}</div>
                        </div>
                      </label>
                    ))}
                  </div>
                  {previewResult.sourceUrl && (
                    <div className="text-xs text-muted-foreground pt-1 border-t flex items-center gap-1">
                      <Globe className="h-3 w-3" />
                      Zdroj: <a href={previewResult.sourceUrl} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline truncate">{previewResult.sourceUrl}</a>
                    </div>
                  )}
                </div>

                <div className="border rounded-lg overflow-hidden">
                  <div className="bg-amber-50 dark:bg-amber-950/30 px-4 py-2 border-b flex items-center gap-2">
                    <AlertTriangle className="h-4 w-4 text-amber-600" />
                    <span className="text-sm font-medium text-amber-800 dark:text-amber-300">Kontrola duplicít</span>
                    {matchLoading && <Loader2 className="h-3 w-3 animate-spin text-amber-600" />}
                  </div>
                  <div className="p-3">
                    {matchLoading ? (
                      <div className="text-xs text-muted-foreground py-2 text-center">Porovnávam s existujúcimi záznamami...</div>
                    ) : existingMatches.length === 0 ? (
                      <div className="text-xs text-green-600 dark:text-green-400 py-1 flex items-center gap-1.5">
                        <CheckCircle2 className="h-3.5 w-3.5" />
                        Žiadne duplicity. Kontakt je nový.
                      </div>
                    ) : (
                      <div className="space-y-2">
                        <div className="text-xs text-amber-700 dark:text-amber-400">
                          Nájdených {existingMatches.length} podobných záznamov:
                        </div>
                        {existingMatches.map((m: any) => (
                          <div
                            key={m.id}
                            className={`border rounded-lg p-2.5 cursor-pointer transition-colors ${
                              selectedMatch?.id === m.id ? "border-primary bg-primary/5" : "hover:bg-accent/50"
                            }`}
                            onClick={() => {
                              setSelectedMatch(selectedMatch?.id === m.id ? null : m);
                              const allChecked: Record<string, boolean> = {};
                              if (m.changes) Object.keys(m.changes).forEach(k => allChecked[k] = true);
                              setSelectedChanges(allChecked);
                            }}
                            data-testid={`match-${m.id}`}
                          >
                            <div className="flex items-center justify-between mb-1">
                              <span className="text-sm font-medium">{m.name}</span>
                              <span className={`text-[10px] px-1.5 py-0.5 rounded font-medium ${
                                m.matchScore >= 60 ? "bg-red-100 text-red-700" : "bg-yellow-100 text-yellow-700"
                              }`}>
                                Zhoda: {m.matchScore}%
                              </span>
                            </div>
                            {selectedMatch?.id === m.id && Object.keys(m.changes).length > 0 && (
                              <div className="mt-2 space-y-1.5">
                                <div className="text-[11px] font-medium text-muted-foreground">Zmeny na aplikovanie:</div>
                                {Object.entries(m.changes).map(([field, vals]: [string, any]) => (
                                  <label key={field} className="flex items-start gap-2 text-xs cursor-pointer hover:bg-accent/30 rounded px-1 py-0.5">
                                    <input
                                      type="checkbox"
                                      className="mt-0.5 rounded"
                                      checked={selectedChanges[field] || false}
                                      onChange={(e) => setSelectedChanges({ ...selectedChanges, [field]: e.target.checked })}
                                    />
                                    <div className="flex-1 min-w-0">
                                      <span className="font-medium text-muted-foreground">{field}:</span>
                                      <div className="flex flex-wrap gap-1 mt-0.5">
                                        {vals.old && (
                                          <span className="bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 line-through px-1 rounded text-[11px]">{vals.old}</span>
                                        )}
                                        <span className="text-muted-foreground">&rarr;</span>
                                        <span className="bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 px-1 rounded text-[11px]">{vals.new}</span>
                                      </div>
                                    </div>
                                  </label>
                                ))}
                              </div>
                            )}
                            {selectedMatch?.id === m.id && Object.keys(m.changes).length === 0 && (
                              <div className="text-xs text-muted-foreground mt-1">Žiadne nové údaje na aktualizáciu</div>
                            )}
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                </div>

                {!selectedMatch && (
                  <div className="bg-primary/5 rounded-lg p-3 border border-primary/20">
                    <div className="text-xs text-muted-foreground mb-1">Uložiť ako nový záznam do modulu:</div>
                    <div className="flex gap-2 mt-1.5">
                      {[
                        { value: "hospitals", label: "Nemocnice", icon: <Building className="h-3.5 w-3.5" /> },
                        { value: "clinics", label: "Ambulancie", icon: <User className="h-3.5 w-3.5" /> },
                        { value: "collaborators", label: "Spolupracovníci", icon: <Users className="h-3.5 w-3.5" /> },
                      ].map(m => (
                        <button key={m.value} data-testid={`module-${m.value}`} className={cn("flex items-center gap-1.5 px-3 py-1.5 rounded-md border text-sm font-medium transition-all", assignModule === m.value ? "border-primary bg-primary text-primary-foreground" : "border-border hover:border-primary/40 hover:bg-primary/5")} onClick={() => setAssignModule(m.value)}>
                          {m.icon} {m.label}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          })()}
          <DialogFooter className="gap-2 flex-wrap">
            <Button variant="outline" onClick={() => { setPreviewResult(null); setSelectedMatch(null); setExistingMatches([]); }} data-testid="button-cancel-assign">
              Zrušiť
            </Button>
            {selectedMatch && Object.keys(selectedMatch.changes || {}).length > 0 ? (
              <Button onClick={updateExisting} disabled={isAssigning} variant="default" data-testid="button-update-existing" className="bg-amber-600 hover:bg-amber-700">
                {isAssigning ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <RefreshCw className="h-4 w-4 mr-2" />}
                Aktualizovať existujúci
              </Button>
            ) : null}
            <Button onClick={confirmAssign} disabled={isAssigning} data-testid="button-confirm-assign">
              {isAssigning ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Plus className="h-4 w-4 mr-2" />}
              {existingMatches.length > 0 ? "Vytvoriť nový" : "Potvrdiť a priradiť"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

    </div>
    )}

      {activeSubTab === "templates" && (
        <div className="space-y-4">
          <Card>
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <div>
                  <CardTitle className="text-base flex items-center gap-2"><Layers className="h-4 w-4" /> Viacjazykové šablóny vyhľadávania</CardTitle>
                  <p className="text-xs text-muted-foreground mt-1">Predpripravené vyhľadávacie scenáre v lokálnych jazykoch pre každú krajinu</p>
                </div>
                <div className="flex gap-2">
                  {!templateSeeded && (
                    <Button variant="default" size="sm" className="text-xs" data-testid="button-seed-templates" onClick={async () => {
                      const resp = await fetch("/api/query-templates/seed", { method: "POST", credentials: "include" });
                      const data = await resp.json();
                      setTemplateSeeded(true);
                      refetchTemplates();
                      toast({ title: `${data.seeded} šablón pridaných`, description: `Celkom: ${data.total}` });
                    }}>
                      <Sparkles className="h-3 w-3 mr-1" /> Načítať prednastavené šablóny
                    </Button>
                  )}
                </div>
              </div>
            </CardHeader>
            <CardContent>
              {queryTemplatesList.length === 0 ? (
                <div className="text-center text-muted-foreground py-8">
                  <Layers className="h-8 w-8 mx-auto mb-2 opacity-50" />
                  <p>Žiadne šablóny. Kliknite na "Načítať prednastavené šablóny" pre importovanie viacjazykových šablón.</p>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="flex flex-wrap gap-2 mb-3">
                    {["all", "sk", "cs", "de", "hu", "ro", "it"].map(lang => (
                      <button key={lang} className={cn("px-3 py-1.5 rounded-md text-xs font-medium border transition-all",
                        (reviewFilter === lang || (lang === "all" && reviewFilter === "all")) ? "border-primary bg-primary/10 text-primary" : "hover:border-primary/30"
                      )} onClick={() => setReviewFilter(lang)} data-testid={`lang-filter-${lang}`}>
                        {lang === "all" ? "Všetky" : lang === "sk" ? "🇸🇰 SK" : lang === "cs" ? "🇨🇿 CZ" : lang === "de" ? "🇦🇹🇩🇪 DE" : lang === "hu" ? "🇭🇺 HU" : lang === "ro" ? "🇷🇴 RO" : "🇮🇹 IT"}
                        <span className="ml-1 text-muted-foreground">({queryTemplatesList.filter((t: any) => lang === "all" || t.language === lang).length})</span>
                      </button>
                    ))}
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                    {queryTemplatesList.filter((t: any) => reviewFilter === "all" || t.language === reviewFilter).map((template: any) => (
                      <div key={template.id} className="rounded-lg border p-3 hover:border-primary/30 transition-all" data-testid={`template-${template.id}`}>
                        <div className="flex items-start justify-between mb-1.5">
                          <div className="flex items-center gap-1.5">
                            <span className="text-[10px] font-medium bg-primary/10 text-primary px-1.5 py-0.5 rounded">{template.language?.toUpperCase()}</span>
                            <span className="text-[10px] text-muted-foreground">{template.country}</span>
                          </div>
                          {template.isBuiltIn && <span className="text-[9px] text-muted-foreground bg-muted px-1.5 py-0.5 rounded">Built-in</span>}
                        </div>
                        <h4 className="text-sm font-semibold mb-0.5">{template.name}</h4>
                        {template.description && <p className="text-[11px] text-muted-foreground mb-2">{template.description}</p>}
                        <div className="flex flex-wrap gap-1 mb-2">
                          {template.segment && <span className="inline-flex items-center gap-0.5 text-[9px] bg-violet-50 dark:bg-violet-900/20 text-violet-700 dark:text-violet-300 px-1.5 py-0.5 rounded"><Layers className="h-2.5 w-2.5" />{template.segment}</span>}
                          {template.keywords && <span className="inline-flex items-center gap-0.5 text-[9px] bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-300 px-1.5 py-0.5 rounded"><Key className="h-2.5 w-2.5" />{template.keywords?.split(",").slice(0, 3).join(", ")}...</span>}
                        </div>
                        <div className="flex items-center justify-between">
                          <span className="text-[9px] text-muted-foreground">Použité: {template.usageCount || 0}x</span>
                          <div className="flex gap-1">
                            <Button size="sm" variant="default" className="h-6 text-[10px] px-2" data-testid={`use-template-${template.id}`} onClick={async () => {
                              await fetch(`/api/query-templates/${template.id}/use`, { method: "POST", credentials: "include" });
                              setSearchForm(f => ({
                                ...f,
                                name: template.name,
                                targetModule: template.targetModule as any,
                                country: template.country || "",
                                segment: template.segment || "",
                                location: template.location || "",
                                keywords: template.keywords || "",
                              }));
                              setActiveSubTab("search");
                              refetchTemplates();
                              toast({ title: "Šablóna použitá" });
                            }}>
                              <ArrowRight className="h-3 w-3 mr-0.5" /> Použiť
                            </Button>
                            {!template.isBuiltIn && (
                              <Button size="sm" variant="ghost" className="h-6 text-[10px] px-1.5 text-red-600" data-testid={`delete-template-${template.id}`} onClick={async () => {
                                await fetch(`/api/query-templates/${template.id}`, { method: "DELETE", credentials: "include" });
                                refetchTemplates();
                              }}>
                                <Trash2 className="h-3 w-3" />
                              </Button>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {activeSubTab === "webhooks" && (
        <div className="space-y-4">
          <Card>
            <CardHeader className="pb-3">
              <div className="flex items-center justify-between">
                <div>
                  <CardTitle className="text-base flex items-center gap-2"><Bell className="h-4 w-4" /> Webhooky</CardTitle>
                  <p className="text-xs text-muted-foreground mt-1">Automatické notifikácie pri nových leadoch, schváleniach a zlúčeniach</p>
                </div>
                <Button variant="default" size="sm" className="text-xs" data-testid="button-new-webhook" onClick={() => setShowWebhookForm(!showWebhookForm)}>
                  <Plus className="h-3 w-3 mr-1" /> Nový webhook
                </Button>
              </div>
            </CardHeader>
            <CardContent>
              {showWebhookForm && (
                <div className="rounded-lg border p-4 mb-4 space-y-3">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    <div>
                      <label className="text-xs font-medium mb-1 block">Názov</label>
                      <Input data-testid="input-webhook-name" placeholder="napr. Slack notifikácie" value={webhookForm.name} onChange={e => setWebhookForm({ ...webhookForm, name: e.target.value })} />
                    </div>
                    <div>
                      <label className="text-xs font-medium mb-1 block">URL</label>
                      <Input data-testid="input-webhook-url" placeholder="https://hooks.slack.com/..." value={webhookForm.url} onChange={e => setWebhookForm({ ...webhookForm, url: e.target.value })} />
                    </div>
                  </div>
                  <div>
                    <label className="text-xs font-medium mb-1.5 block">Udalosti</label>
                    <div className="flex flex-wrap gap-1.5">
                      {["*", "result.reviewed", "result.merged", "results.bulk_reviewed", "campaign.completed"].map(evt => (
                        <button key={evt} className={cn("text-[10px] px-2 py-1 rounded-md border transition-all",
                          webhookForm.events.includes(evt) ? "border-primary bg-primary/10 text-primary font-medium" : "hover:border-primary/30"
                        )} onClick={() => setWebhookForm(f => ({ ...f, events: f.events.includes(evt) ? f.events.filter(e => e !== evt) : [...f.events, evt] }))}>
                          {evt === "*" ? "Všetky" : evt === "result.reviewed" ? "Recenzia" : evt === "result.merged" ? "Zlúčenie" : evt === "results.bulk_reviewed" ? "Hromadná recenzia" : "Kampaň dokončená"}
                        </button>
                      ))}
                    </div>
                  </div>
                  <div>
                    <label className="text-xs font-medium mb-1 block">Secret (voliteľné)</label>
                    <Input data-testid="input-webhook-secret" placeholder="HMAC SHA-256 secret" type="password" value={webhookForm.secret} onChange={e => setWebhookForm({ ...webhookForm, secret: e.target.value })} />
                  </div>
                  <div className="flex gap-2">
                    <Button size="sm" data-testid="button-save-webhook" onClick={async () => {
                      if (!webhookForm.name || !webhookForm.url) { toast({ title: "Vyplňte názov a URL", variant: "destructive" }); return; }
                      await fetch("/api/webhooks", { method: "POST", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify(webhookForm) });
                      refetchWebhooks();
                      setShowWebhookForm(false);
                      setWebhookForm({ name: "", url: "", events: ["*"], secret: "" });
                      toast({ title: "Webhook pridaný" });
                    }}>
                      <Save className="h-3 w-3 mr-1" /> Uložiť
                    </Button>
                    <Button variant="outline" size="sm" onClick={() => setShowWebhookForm(false)}>Zrušiť</Button>
                  </div>
                </div>
              )}

              {webhooksList.length === 0 && !showWebhookForm ? (
                <div className="text-center text-muted-foreground py-8">
                  <Bell className="h-8 w-8 mx-auto mb-2 opacity-50" />
                  <p>Žiadne webhooky. Pridajte webhook pre automatické notifikácie.</p>
                  <p className="text-[11px] mt-1">Podporované udalosti: nový lead, schválenie, zlúčenie do CRM, dokončenie kampane</p>
                </div>
              ) : (
                <div className="space-y-2">
                  {webhooksList.map((hook: any) => (
                    <div key={hook.id} className="rounded-lg border p-3 flex items-center justify-between" data-testid={`webhook-${hook.id}`}>
                      <div>
                        <div className="flex items-center gap-2 mb-0.5">
                          <span className="font-medium text-sm">{hook.name}</span>
                          <span className={cn("text-[10px] px-1.5 py-0.5 rounded", hook.isActive ? "bg-green-100 text-green-700" : "bg-gray-100 text-gray-500")}>
                            {hook.isActive ? "Aktívny" : "Neaktívny"}
                          </span>
                          {(hook.failCount || 0) > 0 && <span className="text-[10px] text-red-600">{hook.failCount} chýb</span>}
                        </div>
                        <div className="text-xs text-muted-foreground font-mono">{hook.url}</div>
                        <div className="flex gap-1 mt-1">
                          {(hook.events || []).map((evt: string) => (
                            <span key={evt} className="text-[9px] bg-muted px-1.5 py-0.5 rounded">{evt}</span>
                          ))}
                        </div>
                      </div>
                      <div className="flex items-center gap-1">
                        <Button size="sm" variant="outline" className="h-7 text-xs" data-testid={`test-webhook-${hook.id}`} onClick={async () => {
                          const resp = await fetch(`/api/webhooks/${hook.id}/test`, { method: "POST", credentials: "include" });
                          const data = await resp.json();
                          toast({ title: data.success ? "Test úspešný" : "Test neúspešný", description: `HTTP ${data.status}`, variant: data.success ? "default" : "destructive" });
                        }}>
                          Test
                        </Button>
                        <Button size="sm" variant="outline" className="h-7 text-xs" data-testid={`toggle-webhook-${hook.id}`} onClick={async () => {
                          await fetch(`/api/webhooks/${hook.id}`, { method: "PATCH", headers: { "Content-Type": "application/json" }, credentials: "include", body: JSON.stringify({ isActive: !hook.isActive }) });
                          refetchWebhooks();
                        }}>
                          {hook.isActive ? "Pozastaviť" : "Aktivovať"}
                        </Button>
                        <Button size="sm" variant="ghost" className="h-7 text-xs text-red-600" data-testid={`delete-webhook-${hook.id}`} onClick={async () => {
                          await fetch(`/api/webhooks/${hook.id}`, { method: "DELETE", credentials: "include" });
                          refetchWebhooks();
                        }}>
                          <Trash2 className="h-3 w-3" />
                        </Button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </div>
      )}

      {activeSubTab === "entities" && (
        <EntityGraphTab />
      )}

      {activeSubTab === "feedback" && (
        <FeedbackLearningTab />
      )}

      {activeSubTab === "lifecycle" && (
        <LifecycleTab />
      )}

      <Sheet open={!!historyCampaign} onOpenChange={(o) => { if (!o) { setHistoryCampaign(null); } }}>
        <SheetContent side="right" className="w-full sm:max-w-2xl overflow-y-auto">
          <SheetHeader>
            <SheetTitle className="flex items-center gap-2">
              <ClipboardList className="h-4 w-4" />
              História behov
            </SheetTitle>
            <SheetDescription className="truncate">{historyCampaign?.name}</SheetDescription>
          </SheetHeader>
          {historyCampaign && <CampaignHistory campaignId={historyCampaign.id} />}
        </SheetContent>
      </Sheet>

      <Sheet open={!!historyJobId} onOpenChange={(o) => { if (!o) setHistoryJobId(null); }}>
        <SheetContent side="right" className="w-full sm:max-w-3xl overflow-y-auto">
          <SheetHeader>
            <SheetTitle className="flex items-center gap-2">
              <Search className="h-4 w-4" />
              Výsledky vyhľadávania
            </SheetTitle>
            <SheetDescription className="truncate">{historyJobName}</SheetDescription>
          </SheetHeader>
          {historyJobId && <HistoryJobResults jobId={historyJobId} />}
        </SheetContent>
      </Sheet>

    </div>
  );
}

function HistoryJobResults({ jobId }: { jobId: number }) {
  const { data: results = [], isLoading } = useQuery<any[]>({
    queryKey: ["/api/lead-search/jobs", jobId, "results"],
    queryFn: async () => {
      const r = await fetch(`/api/lead-search/jobs/${jobId}/results`, { credentials: "include" });
      if (!r.ok) return [];
      return r.json();
    },
    enabled: !!jobId,
  });

  const stats = {
    total: results.length,
    new: results.filter((r: any) => r.status === "new").length,
    approved: results.filter((r: any) => r.status === "approved").length,
    rejected: results.filter((r: any) => r.status === "rejected").length,
    merged: results.filter((r: any) => r.status === "merged").length,
  };
  const [filter, setFilter] = useState<"all" | "new" | "approved" | "rejected" | "merged">("all");
  const filtered = filter === "all" ? results : results.filter((r: any) => r.status === filter);

  if (isLoading) {
    return <div className="flex items-center justify-center py-10"><Loader2 className="h-6 w-6 animate-spin text-muted-foreground" /></div>;
  }
  if (results.length === 0) {
    return <div className="py-10 text-center text-sm text-muted-foreground">Žiadne výsledky pre toto vyhľadávanie.</div>;
  }
  return (
    <div className="mt-4 space-y-4">
      <div className="grid grid-cols-5 gap-2">
        {[
          { k: "all", l: "Všetky", v: stats.total, cls: "bg-muted" },
          { k: "new", l: "Nové", v: stats.new, cls: "bg-blue-50 dark:bg-blue-950" },
          { k: "approved", l: "Schválené", v: stats.approved, cls: "bg-green-50 dark:bg-green-950" },
          { k: "rejected", l: "Zamietnuté", v: stats.rejected, cls: "bg-red-50 dark:bg-red-950" },
          { k: "merged", l: "Zlúčené", v: stats.merged, cls: "bg-violet-50 dark:bg-violet-950" },
        ].map(s => (
          <button
            key={s.k}
            onClick={() => setFilter(s.k as any)}
            className={cn(
              "rounded-md border px-2 py-2 text-left transition-all",
              s.cls,
              filter === s.k ? "border-primary ring-1 ring-primary" : "hover-elevate"
            )}
            data-testid={`history-filter-${s.k}`}
          >
            <div className="text-lg font-semibold leading-none">{s.v}</div>
            <div className="text-[10px] text-muted-foreground mt-1">{s.l}</div>
          </button>
        ))}
      </div>
      <div className="space-y-2">
        {filtered.map((r: any) => (
          <div key={r.id} className="border rounded-lg p-3 text-sm space-y-1.5" data-testid={`history-result-${r.id}`}>
            <div className="flex items-start justify-between gap-2">
              <div className="font-semibold truncate flex-1">{r.name || r.title || "—"}</div>
              <span className={cn(
                "text-[10px] px-1.5 py-0.5 rounded-full shrink-0",
                r.status === "merged" ? "bg-violet-100 text-violet-700" :
                r.status === "approved" ? "bg-green-100 text-green-700" :
                r.status === "rejected" ? "bg-red-100 text-red-700" :
                "bg-blue-100 text-blue-700"
              )}>{r.status}</span>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-3 gap-y-1 text-xs text-muted-foreground">
              {r.email && <div className="flex items-center gap-1.5"><Mail className="h-3 w-3" /><span className="truncate">{r.email}</span></div>}
              {r.phone && <div className="flex items-center gap-1.5"><Phone className="h-3 w-3" /><span>{r.phone}</span></div>}
              {(r.city || r.country) && <div className="flex items-center gap-1.5"><MapPin className="h-3 w-3" /><span className="truncate">{[r.city, r.country].filter(Boolean).join(", ")}</span></div>}
              {r.website && <div className="flex items-center gap-1.5"><Globe className="h-3 w-3" /><a href={r.website.startsWith("http") ? r.website : `https://${r.website}`} target="_blank" rel="noreferrer" className="truncate text-blue-600 hover:underline">{r.website}</a></div>}
            </div>
            {r.confidence != null && (
              <div className="text-[10px] text-muted-foreground">Kvalita: {Math.round((r.confidence || 0) * (r.confidence > 1 ? 1 : 100))}%</div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}

